def _write_c_sweep_profiler_summary(
    output_dir: Path,
    *,
    rows: int = 2,
    model: str = "/tmp/model",
    fixture: str = "/tmp/fixture.json",
    warmup_decode_tokens: int = 8,
    max_layers: int = 40,
) -> None:
    profiler_path = output_dir / f"profiler-c{rows}.json"
    retained_path = output_dir / f"native-diagnostic-c{rows}.json"
    trace_dir = output_dir / f"profile-c{rows}"
    trace_dir.mkdir(parents=True, exist_ok=True)
    (trace_dir / "hipengine_kernel_trace.csv").write_text(
        "Kernel_Name,Start_Timestamp,End_Timestamp\nqwen35_batch_decode,0,12345\n"
    )
    retained_launch = shlex.join(
        (*c_sweep._command_env_prefix_parts(), "python3", "scripts/qwen35_batch_retained_bench.py")
    )
    profiler_path.write_text(
        json.dumps(
            {
                "workload": {"concurrency": rows, "prompt_tokens_per_request": 16, "gen_tokens_per_request": 2},
                "profiler": {
                    "artifact_path": str(profiler_path),
                    "rows": rows,
                    "status": "captured",
                    "output_format": "csv",
                    "trace_dir": str(trace_dir),
                    "trace_files": [str(trace_dir / "hipengine_kernel_trace.csv")],
                    "trace_kernel_names": ["qwen35_batch_decode"],
                    "command": (
                        f"rocprofv3 --kernel-trace --output-format csv -d {trace_dir} -- {retained_launch} "
                        f"--model {model} --fixture {fixture} --batch-size {rows} "
                        "--prompt-length 16 --decode-tokens 2 "
                        f"--warmup-decode-tokens {warmup_decode_tokens} --max-layers {max_layers} "
                        f"--json {retained_path} --c1-baseline-json {output_dir / 'native-baseline-c1.json'} "
                        f"--serial-bridge-json {output_dir / f'serial-bridge-c{rows}.json'} "
                        f"--primitive-correctness-json {output_dir / f'primitive-c{rows}.json'} "
                        f"--profiler-json {profiler_path}"
                    ),
                    "expected_kernels_present": True,
                    "expected_kernel_names": ["qwen35_batch_decode"],
                    "kernel_durations_ns": {"qwen35_batch_decode": 12345.0},
                    "total_kernel_duration_ns": 12345.0,
                    "kernel_duration_shares": {"qwen35_batch_decode": 1.0},
                    "kernel_duration_categories_ns": {
                        "attention": 0.0,
                        "moe": 0.0,
                        "projection": 0.0,
                        "sampling": 0.0,
                        "graph_replay": 0.0,
                        "other": 12345.0,
                    },
                    "kernel_duration_category_shares": {
                        "attention": 0.0,
                        "moe": 0.0,
                        "projection": 0.0,
                        "sampling": 0.0,
                        "graph_replay": 0.0,
                        "other": 1.0,
                    },
                    "cpu_side_total_seconds": 10.0,
                    "cpu_side_bottlenecks_seconds": {
                        "load": 1.0,
                        "prefill": 2.0,
                        "warmup_decode": 0.0,
                        "decode": 7.0,
                        "validation": 0.0,
                        "other": 0.0,
                    },
                    "cpu_side_bottleneck_shares": {
                        "load": 0.1,
                        "prefill": 0.2,
                        "warmup_decode": 0.0,
                        "decode": 0.7,
                        "validation": 0.0,
                        "other": 0.0,
                    },
                },
            }
        )
    )


def test_batch_c_sweep_profiler_precondition_requires_sampler_flags_to_match_retained_command(
    tmp_path: Path,
    monkeypatch: pytest.MonkeyPatch,
) -> None:
    monkeypatch.delenv("HIP_VISIBLE_DEVICES", raising=False)
    output_dir = tmp_path / "artifacts"
    output_dir.mkdir()
    _write_c_sweep_profiler_summary(output_dir, rows=2)
    args = build_c_sweep_parser().parse_args(
        [
            "--batch-sizes",
            "2",
            "--output-dir",
            str(output_dir),
            "--prompt-length",
            "16",
            "--decode-tokens",
            "2",
            "--model",
            "/tmp/model",
            "--fixture",
            "/tmp/fixture.json",
            "--batch-sample-mode",
            "batched_lm_head",
            "--batch-sample-eq-ok",
            "--batch-sample-eq-artifact-template",
            "benchmarks/results/sampler-c{c}.json",
        ]
    )
    native = next(command for command in build_sweep_commands(args) if command.category == "native_diagnostic")

    missing_sampler_flags = c_sweep._profiler_summary_precondition(native)
    assert missing_sampler_flags["kind"] == "profiler_summary"
    assert missing_sampler_flags["artifact_path"] == str(output_dir / "profiler-c2.json")
    assert missing_sampler_flags["passed"] is False
    assert "profiler command --batch-sample-mode must match retained command" in missing_sampler_flags["reason"]
    assert "profiler command is missing --batch-sample-eq-ok" in missing_sampler_flags["reason"]

    profiler_path = output_dir / "profiler-c2.json"
    payload = json.loads(profiler_path.read_text())
    payload["profiler"]["command"] = payload["profiler"]["command"].replace(
        f" --json {output_dir / 'native-diagnostic-c2.json'}",
        " --batch-sample-mode batched_lm_head --batch-sample-eq-ok "
        "--batch-sample-eq-artifact benchmarks/results/sampler-c2.json --batch-sample-eq-rows 2"
        f" --json {output_dir / 'native-diagnostic-c2.json'}",
    )
    profiler_path.write_text(json.dumps(payload))

    precondition = c_sweep._profiler_summary_precondition(native)
    assert precondition["passed"] is True
    assert precondition["profiler_command"] == payload["profiler"]["command"]


