def test_batch_c_sweep_profiler_precondition_synthesizes_trace_fields_from_csv(tmp_path: Path) -> None:
    output_dir = tmp_path / "artifacts"
    output_dir.mkdir()
    _write_c_sweep_profiler_summary(output_dir, rows=2)
    trace_dir = output_dir / "profile-c2"
    (trace_dir / "hipengine_kernel_trace.csv").write_text(
        "Kernel_Name,Start_Timestamp,End_Timestamp\n"
        "qwen35_batch_decode,0,100\n"
        "qwen35_batch_decode,100,150\n"
        "qwen35_batch_decode_wmma_caware,150,350\n"
    )
    args = build_c_sweep_parser().parse_args(
        [
            "--batch-sizes",
            "2",
            "--output-dir",
            str(output_dir),
            "--model",
            "/tmp/model",
            "--fixture",
            "/tmp/fixture.json",
            "--prompt-length",
            "16",
            "--decode-tokens",
            "2",
        ]
    )
    profiler_path = output_dir / "profiler-c2.json"
    payload = json.loads(profiler_path.read_text())
    for field in (
        "trace_kernel_names",
        "kernel_durations_ns",
        "total_kernel_duration_ns",
        "kernel_duration_shares",
        "kernel_duration_categories_ns",
        "kernel_duration_category_shares",
    ):
        payload["profiler"].pop(field)
    profiler_path.write_text(json.dumps(payload))
    native = next(command for command in build_sweep_commands(args) if command.category == "native_diagnostic")

    precondition = c_sweep._profiler_summary_precondition(native)

    assert c_sweep._PROFILER_KERNEL_DURATION_CATEGORIES is RETAINED_ARTIFACT_REQUIRED_PROFILER_KERNEL_DURATION_CATEGORIES
    assert c_sweep._PROFILER_CPU_SIDE_BOTTLENECK_CATEGORIES is RETAINED_ARTIFACT_REQUIRED_PROFILER_CPU_SIDE_BOTTLENECK_CATEGORIES
    assert c_sweep._PROFILER_TRACE_KERNEL_NAME_COLUMNS is RETAINED_ARTIFACT_PROFILER_TRACE_KERNEL_NAME_COLUMNS
    assert c_sweep._PROFILER_TRACE_START_COLUMNS is RETAINED_ARTIFACT_PROFILER_TRACE_START_COLUMNS
    assert c_sweep._PROFILER_TRACE_END_COLUMNS is RETAINED_ARTIFACT_PROFILER_TRACE_END_COLUMNS
    assert c_sweep._PROFILER_TRACE_DURATION_COLUMNS is RETAINED_ARTIFACT_PROFILER_TRACE_DURATION_COLUMNS
    assert c_sweep._ROCPROF_COMMAND_FLAGS is RETAINED_ARTIFACT_ROCPROF_COMMAND_FLAGS
    assert c_sweep._ROCPROF_EXECUTABLE is RETAINED_ARTIFACT_ROCPROF_EXECUTABLE
    assert c_sweep._ROCPROF_OUTPUT_FORMAT is RETAINED_ARTIFACT_ROCPROF_OUTPUT_FORMAT
    assert c_sweep._PROFILER_SYNTHESIZED_FIELDS is RETAINED_ARTIFACT_PROFILER_TRACE_SYNTHESIZED_FIELDS
    assert c_sweep._PRIMITIVE_CORRECTNESS_SCRIPT is RETAINED_ARTIFACT_PRIMITIVE_CORRECTNESS_SCRIPT
    assert c_sweep._SERIAL_BRIDGE_SCRIPT is RETAINED_ARTIFACT_SERIAL_BRIDGE_SCRIPT
    assert c_sweep._LEGACY_NATIVE_BENCH_SCRIPT is RETAINED_ARTIFACT_LEGACY_NATIVE_BENCH_SCRIPT
    assert c_sweep._INT8_DIAGNOSTIC_SCRIPT is RETAINED_ARTIFACT_INT8_DIAGNOSTIC_SCRIPT
    assert c_sweep._RETAINED_BENCH_SCRIPT is RETAINED_ARTIFACT_RETAINED_BENCH_SCRIPT
    assert c_sweep._RETAINED_BENCH_UNIQUE_FLAGS is RETAINED_ARTIFACT_RETAINED_BENCH_UNIQUE_FLAGS
    assert c_sweep._RETAINED_PROFILED_COMMAND_DISALLOWED_FLAGS is RETAINED_ARTIFACT_RETAINED_PROFILED_COMMAND_DISALLOWED_FLAGS
    assert c_sweep._RETAINED_PROFILED_COMMAND_UNIQUE_FLAGS is RETAINED_ARTIFACT_RETAINED_PROFILED_COMMAND_UNIQUE_FLAGS
    assert c_sweep._RETAINED_PROFILED_COMMAND_VALUE_FLAGS is RETAINED_ARTIFACT_RETAINED_PROFILED_COMMAND_VALUE_FLAGS
    assert all(flag in c_sweep._SWEEP_COMMAND_KNOWN_FLAGS for flag in RETAINED_ARTIFACT_RETAINED_PROFILED_COMMAND_UNIQUE_FLAGS)
    assert c_sweep._PRIMITIVE_CORRECTNESS_UNIQUE_FLAGS is RETAINED_ARTIFACT_PRIMITIVE_CORRECTNESS_UNIQUE_FLAGS
    assert c_sweep._RETAINED_PRECONDITION_KINDS is RETAINED_ARTIFACT_RETAINED_PRECONDITION_KINDS
    assert c_sweep._RETAINED_POSTCONDITION_KINDS is RETAINED_ARTIFACT_RETAINED_POSTCONDITION_KINDS
    assert c_sweep._RETAINED_CONDITION_STATUS_LABELS is RETAINED_ARTIFACT_RETAINED_CONDITION_STATUS_LABELS
    assert c_sweep._RETAINED_GATE_FLAGS is RETAINED_ARTIFACT_RETAINED_GATE_FLAGS
    assert c_sweep._RETAINED_GATE_LABELS is RETAINED_ARTIFACT_RETAINED_GATE_LABELS
    assert c_sweep._SWEEP_COMMAND_CATEGORIES is RETAINED_ARTIFACT_SWEEP_COMMAND_CATEGORIES
    assert c_sweep._SWEEP_COMMAND_STATUS_LABELS is RETAINED_ARTIFACT_SWEEP_COMMAND_STATUS_LABELS
    assert precondition["kind"] == RETAINED_ARTIFACT_RETAINED_PRECONDITION_KINDS[-1]
    assert precondition["passed"] is True
    assert precondition["profiler_source_artifact_path"] == str(profiler_path)
    assert precondition["profiler_trace_kernel_names"] == ["qwen35_batch_decode", "qwen35_batch_decode_wmma_caware"]
    assert precondition["profiler_trace_synthesized_fields"] == [
        "trace_kernel_names",
        "kernel_durations_ns",
        "total_kernel_duration_ns",
        "kernel_duration_shares",
        "kernel_duration_categories_ns",
        "kernel_duration_category_shares",
    ]
    assert precondition["kernel_durations_ns"] == {"qwen35_batch_decode": 150.0, "qwen35_batch_decode_wmma_caware": 200.0}
    assert precondition["total_kernel_duration_ns"] == 350.0
    assert precondition["kernel_duration_categories_ns"] == {
        "attention": 0.0,
        "moe": 0.0,
        "projection": 200.0,
        "sampling": 0.0,
        "graph_replay": 0.0,
        "other": 150.0,
    }


