def test_batch_c_sweep_summary_json_rejects_nonfinite() -> None:
    with pytest.raises(ValueError, match="Out of range float values"):
        c_sweep._summary_json({"bad": float("inf")})

    assert json.loads(c_sweep._summary_json({"ok": 1.0})) == {"ok": 1.0}


def test_batch_c_sweep_load_json_path_rejects_nonfinite(tmp_path: Path) -> None:
    payload_path = tmp_path / "payload.json"
    payload_path.write_text('{"bad": -Infinity}', encoding="utf-8")
    with pytest.raises(ValueError, match="JSON contains non-finite constant '-Infinity'"):
        c_sweep._load_json_path(payload_path)

    payload_path.write_text('{"ok": 1.0}', encoding="utf-8")
    assert c_sweep._load_json_path(payload_path) == {"ok": 1.0}


def test_batch_c_sweep_plans_retained_sampler_evidence(tmp_path: Path) -> None:
    args = build_c_sweep_parser().parse_args(
        [
            "--dry-run",
            "--batch-sizes",
            "1,2,4",
            "--output-dir",
            str(tmp_path / "artifacts"),
            "--batch-sample-mode",
            "batched_lm_head",
            "--batch-sample-eq-ok",
            "--batch-sample-eq-artifact-template",
            "benchmarks/results/sampler-c{c}.json",
        ]
    )

    planned = build_sweep_commands(args)
    native_commands = [item for item in planned if item.category == "native_diagnostic"]
    native_c1, native_c2, native_c4 = native_commands

    assert "--batch-sample-mode" not in native_c1.argv
    assert "--batch-sample-mode batched_lm_head" in native_c2.command
    assert "--batch-sample-eq-ok" in native_c2.argv
    assert "--batch-sample-eq-artifact benchmarks/results/sampler-c2.json" in native_c2.command
    assert "--batch-sample-eq-rows 2" in native_c2.command
    assert "--batch-sample-eq-artifact benchmarks/results/sampler-c4.json" in native_c4.command
    assert "--batch-sample-eq-rows 4" in native_c4.command

    summary = run_sweep(args)
    c_sweep.validate_sweep_summary(summary)
    persisted_native_c2 = next(
        row for row in summary["commands"] if row["category"] == "native_diagnostic" and row["batch_size"] == 2
    )
    assert "--batch-sample-mode batched_lm_head" in persisted_native_c2["command"]
    assert "--batch-sample-eq-artifact benchmarks/results/sampler-c2.json" in persisted_native_c2["command"]

    tampered_missing_sampler_mode = json.loads(json.dumps(summary))
    native_c2_row = next(
        row for row in tampered_missing_sampler_mode["commands"] if row["category"] == "native_diagnostic" and row["batch_size"] == 2
    )
    mode_index = native_c2_row["argv"].index("--batch-sample-mode")
    del native_c2_row["argv"][mode_index : mode_index + 2]
    native_c2_row["command"] = shlex.join(native_c2_row["argv"])
    with pytest.raises(ValueError, match=r"commands\[\]\.argv --batch-sample-mode must match options\.batch_sample_mode"):
        c_sweep.validate_sweep_summary(tampered_missing_sampler_mode)

    tampered_sampler_artifact = json.loads(json.dumps(summary))
    native_c4_row = next(
        row for row in tampered_sampler_artifact["commands"] if row["category"] == "native_diagnostic" and row["batch_size"] == 4
    )
    artifact_index = native_c4_row["argv"].index("--batch-sample-eq-artifact") + 1
    native_c4_row["argv"][artifact_index] = "benchmarks/results/sampler-c2.json"
    native_c4_row["command"] = shlex.join(native_c4_row["argv"])
    with pytest.raises(ValueError, match=r"commands\[\]\.argv --batch-sample-eq-artifact must match options\.batch_sample_eq_artifact_template"):
        c_sweep.validate_sweep_summary(tampered_sampler_artifact)

    tampered_c1_sampler_flag = json.loads(json.dumps(summary))
    native_c1_row = next(
        row for row in tampered_c1_sampler_flag["commands"] if row["category"] == "native_diagnostic" and row["batch_size"] == 1
    )
    native_c1_row["argv"].extend(["--batch-sample-mode", "batched_lm_head"])
    native_c1_row["command"] = shlex.join(native_c1_row["argv"])
    with pytest.raises(ValueError, match=r"commands\[\]\.argv c=1 native baseline must not include batch sampler evidence flags"):
        c_sweep.validate_sweep_summary(tampered_c1_sampler_flag)


def test_batch_c_sweep_dry_run_records_commands_and_artifacts(tmp_path: Path) -> None:
    summary_path = tmp_path / "summary.json"
    args = build_c_sweep_parser().parse_args(
        [
            "--dry-run",
            "--batch-sizes",
            "1,2",
            "--output-dir",
            str(tmp_path / "artifacts"),
            "--summary-json",
            str(summary_path),
            "--model",
            "/tmp/model",
            "--fixture",
            "/tmp/fixture.json",
            "--prompt-length",
            "16",
            "--decode-tokens",
            "2",
            "--warmup-decode-tokens",
            "1",
            "--max-layers",
            "3",
            "--projection-dispatch-artifact",
            "benchmarks/results/projection-candidates.json",
        ]
    )

    planned = build_sweep_commands(args)
    assert [(item.category, item.batch_size) for item in planned] == [
        ("primitive", 1),
        ("serial_bridge", 1),
        ("native_diagnostic", 1),
        ("primitive", 2),
        ("serial_bridge", 2),
        ("native_diagnostic", 2),
    ]

    summary = run_sweep(args)

    assert summary["status"] == "planned"
    assert summary["dry_run"] is True
    assert summary["options"] == {
        "model": "/tmp/model",
        "fixture": "/tmp/fixture.json",
        "prompt_length": 16,
        "decode_tokens": 2,
        "warmup_decode_tokens": 1,
        "max_layers": 3,
        "seed": 1234,
        "stop_on_failure": True,
        "include_int8": False,
        "include_gguf": False,
        "require_cached_build": False,
        "compiler_version_file": None,
        "projection_dispatch_artifact": "benchmarks/results/projection-candidates.json",
        "batch_sample_mode": None,
        "batch_sample_eq_ok": False,
        "batch_sample_eq_artifact_template": None,
        "batch_sample_eq_rows": None,
    }
    assert summary_path.exists()
    persisted = json.loads(summary_path.read_text())
    assert persisted["options"] == summary["options"]
    assert persisted["command_count"] == 6
    assert persisted["completed_command_count"] == 6
    assert len(persisted["commands"]) == 6
    assert persisted["status_counts"] == {"planned": 6}
    assert persisted["category_status_counts"] == {
        "primitive": {"planned": 2},
        "serial_bridge": {"planned": 2},
        "native_diagnostic": {"planned": 2},
    }
    assert persisted["retained_precondition_counts"] == {}
    assert persisted["skipped_preconditions"] == []
    c_sweep.validate_sweep_summary(persisted)
    with pytest.raises(ValueError, match="summary must be an object"):
        c_sweep.validate_sweep_summary([])  # type: ignore[arg-type]
    tampered_extra_summary_key = json.loads(json.dumps(persisted))
    tampered_extra_summary_key["unexpected"] = "field"
    with pytest.raises(ValueError, match="summary must contain exactly the c-sweep schema keys"):
        c_sweep.validate_sweep_summary(tampered_extra_summary_key)
    tampered_missing_summary_key = json.loads(json.dumps(persisted))
    tampered_missing_summary_key.pop("failed_postconditions")
    with pytest.raises(ValueError, match="summary must contain exactly the c-sweep schema keys"):
        c_sweep.validate_sweep_summary(tampered_missing_summary_key)
    tampered_extra_command_key = json.loads(json.dumps(persisted))
    tampered_extra_command_key["commands"][0]["unexpected"] = "field"
    with pytest.raises(ValueError, match=r"commands\[\] must contain only c-sweep schema keys"):
        c_sweep.validate_sweep_summary(tampered_extra_command_key)
    tampered_extra_git_key = json.loads(json.dumps(persisted))
    tampered_extra_git_key["git"]["unexpected"] = "field"
    with pytest.raises(ValueError, match="git must contain exactly the c-sweep provenance keys"):
        c_sweep.validate_sweep_summary(tampered_extra_git_key)
    tampered_missing_planned_returncode = json.loads(json.dumps(persisted))
    tampered_missing_planned_returncode["commands"][0].pop("returncode")
    with pytest.raises(ValueError, match=r"commands\[\] planned rows must contain exactly planned command keys"):
        c_sweep.validate_sweep_summary(tampered_missing_planned_returncode)
    tampered_missing_git_key = json.loads(json.dumps(persisted))
    tampered_missing_git_key["git"].pop("status_short")
    with pytest.raises(ValueError, match="git must contain exactly the c-sweep provenance keys"):
        c_sweep.validate_sweep_summary(tampered_missing_git_key)
    tampered_schema_bool = json.loads(json.dumps(persisted))
    tampered_schema_bool["schema"] = True
    with pytest.raises(ValueError, match="schema must be typed int 1"):
        c_sweep.validate_sweep_summary(tampered_schema_bool)
    tampered_schema_string = json.loads(json.dumps(persisted))
    tampered_schema_string["schema"] = "1"
    with pytest.raises(ValueError, match="schema must be typed int 1"):
        c_sweep.validate_sweep_summary(tampered_schema_string)
    tampered_dry_run_type = json.loads(json.dumps(persisted))
    tampered_dry_run_type["dry_run"] = "true"
    with pytest.raises(ValueError, match="dry_run must be a bool"):
        c_sweep.validate_sweep_summary(tampered_dry_run_type)
    tampered_extra_option = json.loads(json.dumps(persisted))
    tampered_extra_option["options"]["unexpected"] = "field"
    with pytest.raises(ValueError, match="options must contain exactly the c-sweep schema keys"):
        c_sweep.validate_sweep_summary(tampered_extra_option)
    tampered_missing_option = json.loads(json.dumps(persisted))
    tampered_missing_option["options"].pop("compiler_version_file")
    with pytest.raises(ValueError, match="options must contain exactly the c-sweep schema keys"):
        c_sweep.validate_sweep_summary(tampered_missing_option)
    for option in ("model", "fixture"):
        tampered_blank_label = json.loads(json.dumps(persisted))
        tampered_blank_label["options"][option] = "   "
        with pytest.raises(ValueError, match=rf"options\.{option} must be a non-empty string"):
            c_sweep.validate_sweep_summary(tampered_blank_label)
    for bad_batch_sizes in ([True], [2, 2], [0], ["2"]):
        tampered_batch_sizes = json.loads(json.dumps(persisted))
        tampered_batch_sizes["batch_sizes"] = bad_batch_sizes
        with pytest.raises(ValueError, match="batch_sizes must be a non-empty unique positive-int list"):
            c_sweep.validate_sweep_summary(tampered_batch_sizes)
    for bad_command_count in (True, "6", 5):
        tampered_command_count = json.loads(json.dumps(persisted))
        tampered_command_count["command_count"] = bad_command_count
        with pytest.raises(ValueError, match="command_count must be an int greater than or equal to completed_command_count"):
            c_sweep.validate_sweep_summary(tampered_command_count)
    tampered_completed_count_type = json.loads(json.dumps(persisted))
    tampered_completed_count_type["completed_command_count"] = "6"
    with pytest.raises(ValueError, match=r"completed_command_count must be a typed int matching len\(commands\)"):
        c_sweep.validate_sweep_summary(tampered_completed_count_type)
    tampered_completed_count_bool = json.loads(json.dumps(persisted))
    tampered_completed_count_bool["commands"] = tampered_completed_count_bool["commands"][:1]
    tampered_completed_count_bool["completed_command_count"] = True
    tampered_completed_count_bool["status_counts"] = {"planned": 1}
    tampered_completed_count_bool["category_status_counts"] = {"primitive": {"planned": 1}}
    with pytest.raises(ValueError, match=r"completed_command_count must be a typed int matching len\(commands\)"):
        c_sweep.validate_sweep_summary(tampered_completed_count_bool)
    tampered_status_count_bool = json.loads(json.dumps(persisted))
    tampered_status_count_bool["commands"] = tampered_status_count_bool["commands"][:1]
    tampered_status_count_bool["completed_command_count"] = 1
    tampered_status_count_bool["status_counts"] = {"planned": True}
    tampered_status_count_bool["category_status_counts"] = {"primitive": {"planned": 1}}
    with pytest.raises(ValueError, match="status_counts must contain only non-negative integer count values"):
        c_sweep.validate_sweep_summary(tampered_status_count_bool)
    tampered_category_status_count_bool = json.loads(json.dumps(persisted))
    tampered_category_status_count_bool["commands"] = tampered_category_status_count_bool["commands"][:1]
    tampered_category_status_count_bool["completed_command_count"] = 1
    tampered_category_status_count_bool["status_counts"] = {"planned": 1}
    tampered_category_status_count_bool["category_status_counts"] = {"primitive": {"planned": True}}
    with pytest.raises(ValueError, match="category_status_counts must contain only non-negative integer count values"):
        c_sweep.validate_sweep_summary(tampered_category_status_count_bool)
    tampered_dropped_commands = json.loads(json.dumps(persisted))
    tampered_dropped_commands["commands"] = []
    tampered_dropped_commands["completed_command_count"] = 0
    with pytest.raises(ValueError, match="status_counts must match commands"):
        c_sweep.validate_sweep_summary(tampered_dropped_commands)
    tampered_empty_commands = json.loads(json.dumps(persisted))
    tampered_empty_commands["commands"] = []
    tampered_empty_commands["command_count"] = 0
    tampered_empty_commands["completed_command_count"] = 0
    tampered_empty_commands["status_counts"] = {}
    tampered_empty_commands["category_status_counts"] = {}
    with pytest.raises(ValueError, match="commands must be a non-empty list"):
        c_sweep.validate_sweep_summary(tampered_empty_commands)
    tampered_partial_dry_run = json.loads(json.dumps(persisted))
    tampered_partial_dry_run["commands"] = tampered_partial_dry_run["commands"][:3]
    tampered_partial_dry_run["completed_command_count"] = 3
    tampered_partial_dry_run["status_counts"] = {"planned": 3}
    tampered_partial_dry_run["category_status_counts"] = {
        "primitive": {"planned": 1},
        "serial_bridge": {"planned": 1},
        "native_diagnostic": {"planned": 1},
    }
    with pytest.raises(ValueError, match="dry-run summaries must include all planned commands"):
        c_sweep.validate_sweep_summary(tampered_partial_dry_run)
    tampered_dry_run_status = json.loads(json.dumps(persisted))
    tampered_dry_run_status["commands"][0]["status"] = "passed"
    with pytest.raises(ValueError, match=r"commands\[\]\.status must be planned for dry-run summaries"):
        c_sweep.validate_sweep_summary(tampered_dry_run_status)
    tampered_planned_duration = json.loads(json.dumps(persisted))
    tampered_planned_duration["commands"][0]["duration_seconds"] = 0.1
    with pytest.raises(ValueError, match=r"commands\[\]\.duration_seconds must be zero for planned rows"):
        c_sweep.validate_sweep_summary(tampered_planned_duration)
    tampered_planned_output = json.loads(json.dumps(persisted))
    tampered_planned_output["commands"][0]["output_tail"] = "dry-run output"
    with pytest.raises(ValueError, match=r"commands\[\]\.output_tail must be absent for planned rows"):
        c_sweep.validate_sweep_summary(tampered_planned_output)
    tampered_planned_condition = json.loads(json.dumps(persisted))
    tampered_planned_condition["commands"][0]["preconditions"] = [
        {"kind": "primitive_correctness", "passed": True}
    ]
    with pytest.raises(ValueError, match=r"commands\[\]\.conditions must be absent for planned rows"):
        c_sweep.validate_sweep_summary(tampered_planned_condition)
    assert all(entry["status"] == "planned" for entry in persisted["commands"])
    assert all(entry["command"] for entry in persisted["commands"])
    assert all(entry["artifact_path"] for entry in persisted["commands"])
    assert all("git_dirty" in entry for entry in persisted["commands"])
    assert any("qwen35_batch_retained_bench.py" in entry["command"] for entry in persisted["commands"])
    assert any("qwen35_paro_bench.py" in entry["command"] for entry in persisted["commands"])
    retained_c1 = next(item for item in planned if item.category == "native_diagnostic" and item.batch_size == 1)
    assert "--projection-dispatch-artifact" not in retained_c1.argv
    retained_c2 = next(item for item in planned if item.category == "native_diagnostic" and item.batch_size == 2)
    assert "--projection-dispatch-artifact" in retained_c2.argv
    assert "benchmarks/results/projection-candidates.json" in retained_c2.argv
    assert "--c1-baseline-json" in retained_c2.argv
    assert str(tmp_path / "artifacts" / "native-baseline-c1.json") in retained_c2.argv
    assert "--serial-bridge-json" in retained_c2.argv
    assert str(tmp_path / "artifacts" / "serial-bridge-c2.json") in retained_c2.argv
    assert "--primitive-correctness-json" in retained_c2.argv
    assert str(tmp_path / "artifacts" / "primitive-c2.json") in retained_c2.argv
    assert "--profiler-json" in retained_c2.argv
    assert str(tmp_path / "artifacts" / "profiler-c2.json") in retained_c2.argv

    retained_c2_entry_index = next(
        index
        for index, entry in enumerate(persisted["commands"])
        if entry["category"] == "native_diagnostic" and entry["batch_size"] == 2
    )
    missing_projection_flag = json.loads(json.dumps(persisted))
    missing_projection_argv = missing_projection_flag["commands"][retained_c2_entry_index]["argv"]
    projection_flag_index = missing_projection_argv.index("--projection-dispatch-artifact")
    del missing_projection_argv[projection_flag_index : projection_flag_index + 2]
    missing_projection_flag["commands"][retained_c2_entry_index]["command"] = shlex.join(missing_projection_argv)
    with pytest.raises(ValueError, match="--projection-dispatch-artifact must match options.projection_dispatch_artifact"):
        c_sweep.validate_sweep_summary(missing_projection_flag)

    missing_projection_option = json.loads(json.dumps(persisted))
    missing_projection_option["options"]["projection_dispatch_artifact"] = None
    with pytest.raises(ValueError, match="--projection-dispatch-artifact requires options.projection_dispatch_artifact"):
        c_sweep.validate_sweep_summary(missing_projection_option)

    retained_c1_entry_index = next(
        index
        for index, entry in enumerate(persisted["commands"])
        if entry["category"] == "native_diagnostic" and entry["batch_size"] == 1
    )
    c1_projection_flag = json.loads(json.dumps(persisted))
    c1_projection_argv = c1_projection_flag["commands"][retained_c1_entry_index]["argv"]
    c1_projection_argv.extend(["--projection-dispatch-artifact", "benchmarks/results/projection-candidates.json"])
    c1_projection_flag["commands"][retained_c1_entry_index]["command"] = shlex.join(c1_projection_argv)
    with pytest.raises(ValueError, match="c=1 native baseline must not include --projection-dispatch-artifact"):
        c_sweep.validate_sweep_summary(c1_projection_flag)


def test_batch_c_sweep_records_visible_hip_device_env_in_commands(
    tmp_path: Path,
    monkeypatch: pytest.MonkeyPatch,
) -> None:
    monkeypatch.setenv("HIP_VISIBLE_DEVICES", "1")
    summary_path = tmp_path / "summary.json"
    args = build_c_sweep_parser().parse_args(
        [
            "--dry-run",
            "--batch-sizes",
            "1,2",
            "--output-dir",
            str(tmp_path / "artifacts"),
            "--summary-json",
            str(summary_path),
            "--model",
            "/tmp/model",
            "--fixture",
            "/tmp/fixture.json",
            "--prompt-length",
            "16",
            "--decode-tokens",
            "2",
            "--warmup-decode-tokens",
            "1",
            "--max-layers",
            "3",
        ]
    )

    planned = build_sweep_commands(args)
    summary = run_sweep(args)
    persisted = json.loads(summary_path.read_text())

    assert all(item.argv[:2] == ("env", "HIP_VISIBLE_DEVICES=1") for item in planned)
    assert all(entry["argv"][:2] == ["env", "HIP_VISIBLE_DEVICES=1"] for entry in persisted["commands"])
    assert all(entry["command"].startswith("env HIP_VISIBLE_DEVICES=1 ") for entry in persisted["commands"])
    assert all(c_sweep._strip_command_env_prefix(entry["argv"])[1].startswith("scripts/") for entry in persisted["commands"])
    assert summary["status"] == "planned"
    c_sweep.validate_sweep_summary(persisted)

    blank_env_summary = json.loads(json.dumps(persisted))
    blank_env_summary["commands"][0]["argv"][1] = "HIP_VISIBLE_DEVICES=   "
    blank_env_summary["commands"][0]["command"] = shlex.join(blank_env_summary["commands"][0]["argv"])
    with pytest.raises(ValueError, match=r"commands\[\]\.argv device env prefix values must be non-blank"):
        c_sweep.validate_sweep_summary(blank_env_summary)


def test_batch_c_sweep_omits_blank_visible_hip_device_env_from_commands(
    tmp_path: Path,
    monkeypatch: pytest.MonkeyPatch,
) -> None:
    monkeypatch.setenv("HIP_VISIBLE_DEVICES", "   ")
    summary_path = tmp_path / "summary.json"
    args = build_c_sweep_parser().parse_args(
        [
            "--dry-run",
            "--batch-sizes",
            "1,2",
            "--output-dir",
            str(tmp_path / "artifacts"),
            "--summary-json",
            str(summary_path),
            "--model",
            "/tmp/model",
            "--fixture",
            "/tmp/fixture.json",
            "--prompt-length",
            "16",
            "--decode-tokens",
            "2",
            "--warmup-decode-tokens",
            "1",
            "--max-layers",
            "3",
        ]
    )

    planned = build_sweep_commands(args)
    summary = run_sweep(args)
    persisted = json.loads(summary_path.read_text())

    assert all(item.argv[0] != "env" for item in planned)
    assert all(entry["argv"][0] != "env" for entry in persisted["commands"])
    assert all(not entry["command"].startswith("env HIP_VISIBLE_DEVICES=") for entry in persisted["commands"])
    assert summary["status"] == "planned"
    c_sweep.validate_sweep_summary(persisted)


def test_retained_bench_projection_dispatch_artifact_env_and_payload(tmp_path: Path, monkeypatch: pytest.MonkeyPatch) -> None:
    artifact_dir = tmp_path / "benchmarks" / "results"
