def test_retained_bench_defaults_to_valid_batched_sampler_artifact(tmp_path: Path, monkeypatch: pytest.MonkeyPatch) -> None:
    artifact_dir = tmp_path / "benchmarks" / "results"
    artifact_dir.mkdir(parents=True)
    artifact_path = retained_bench._DEFAULT_BATCH_SAMPLE_EQ_ARTIFACT_TEMPLATE.format(rows=4)
    (tmp_path / artifact_path).write_text(
        json.dumps(_sampler_equality_payload(rows=4, artifact_path=artifact_path)),
        encoding="utf-8",
    )
    monkeypatch.chdir(tmp_path)

    args = SimpleNamespace(
        batch_size=4,
        batch_sample_mode="serial_lm_head",
        batch_sample_eq_ok=False,
        batch_sample_eq_artifact=None,
        batch_sample_eq_rows=None,
    )
    retained_bench._apply_default_batch_sample_evidence(args, [])

    assert args.batch_sample_mode == "batched_lm_head"
    assert args.batch_sample_eq_ok is True
    assert args.batch_sample_eq_artifact == Path(artifact_path)
    assert args.batch_sample_eq_rows == 4

    retained_bench._apply_runtime_env_args(SimpleNamespace(projection_dispatch_artifact=None, **vars(args)))
    assert os.environ["HIPENGINE_QWEN35_BATCH_SAMPLE_MODE"] == "batched_lm_head"
    assert os.environ["HIPENGINE_QWEN35_BATCH_SAMPLE_C2_EQ_OK"] == "1"
    assert os.environ["HIPENGINE_QWEN35_BATCH_SAMPLE_EQ_ARTIFACT"] == artifact_path
    assert os.environ["HIPENGINE_QWEN35_BATCH_SAMPLE_EQ_ROWS"] == "4"

    c2_artifact_path = retained_bench._DEFAULT_BATCH_SAMPLE_EQ_ARTIFACT_TEMPLATE.format(rows=2)
    (tmp_path / c2_artifact_path).write_text(
        json.dumps(_sampler_equality_payload(rows=2, artifact_path=c2_artifact_path)),
        encoding="utf-8",
    )
    c2_default = SimpleNamespace(
        batch_size=2,
        batch_sample_mode="serial_lm_head",
        batch_sample_eq_ok=False,
        batch_sample_eq_artifact=None,
        batch_sample_eq_rows=None,
    )
    retained_bench._apply_default_batch_sample_evidence(c2_default, [])
    assert c2_default.batch_sample_mode == "batched_lm_head"
    assert c2_default.batch_sample_eq_ok is True
    assert c2_default.batch_sample_eq_artifact == Path(c2_artifact_path)
    assert c2_default.batch_sample_eq_rows == 2
    assert not hasattr(c2_default, "batch_sample_stabilize_cast_elems")

    retained_bench._apply_runtime_env_args(SimpleNamespace(projection_dispatch_artifact=None, **vars(c2_default)))
    assert os.environ["HIPENGINE_QWEN35_BATCH_SAMPLE_MODE"] == "batched_lm_head"
    assert os.environ["HIPENGINE_QWEN35_BATCH_SAMPLE_EQ_ARTIFACT"] == c2_artifact_path
    assert os.environ["HIPENGINE_QWEN35_BATCH_SAMPLE_EQ_ROWS"] == "2"
    assert os.environ["HIPENGINE_QWEN35_BATCH_SAMPLE_STABILIZE_CAST_ELEMS"] == "0"

    c8_artifact_path = retained_bench._DEFAULT_BATCH_SAMPLE_EQ_ARTIFACT_TEMPLATE.format(rows=8)
    (tmp_path / c8_artifact_path).write_text(
        json.dumps(_sampler_equality_payload(rows=8, artifact_path=c8_artifact_path)),
        encoding="utf-8",
    )
    c8_default = SimpleNamespace(
        batch_size=8,
        batch_sample_mode="serial_lm_head",
        batch_sample_eq_ok=False,
        batch_sample_eq_artifact=None,
        batch_sample_eq_rows=None,
    )
    retained_bench._apply_default_batch_sample_evidence(c8_default, [])
    assert c8_default.batch_sample_mode == "batched_lm_head"
    assert c8_default.batch_sample_eq_ok is True
    assert c8_default.batch_sample_eq_artifact == Path(c8_artifact_path)
    assert c8_default.batch_sample_eq_rows == 8
    assert c8_default.batch_sample_stabilize_cast_elems == 256

    retained_bench._apply_runtime_env_args(SimpleNamespace(projection_dispatch_artifact=None, **vars(c8_default)))
    assert os.environ["HIPENGINE_QWEN35_BATCH_SAMPLE_MODE"] == "batched_lm_head"
    assert os.environ["HIPENGINE_QWEN35_BATCH_SAMPLE_EQ_ARTIFACT"] == c8_artifact_path
    assert os.environ["HIPENGINE_QWEN35_BATCH_SAMPLE_EQ_ROWS"] == "8"
    assert os.environ["HIPENGINE_QWEN35_BATCH_SAMPLE_STABILIZE_CAST_ELEMS"] == "256"

    explicit_serial = SimpleNamespace(
        batch_size=4,
        batch_sample_mode="serial_lm_head",
        batch_sample_eq_ok=False,
        batch_sample_eq_artifact=None,
        batch_sample_eq_rows=None,
    )
    retained_bench._apply_default_batch_sample_evidence(explicit_serial, ["--batch-sample-mode", "serial_lm_head"])
    assert explicit_serial.batch_sample_mode == "serial_lm_head"
    assert explicit_serial.batch_sample_eq_artifact is None
    _clear_qwen35_batch_env()


def test_retained_bench_auto_full_attention_rowchunk_cap_tracks_equality_frontier() -> None:
    """The correctness-first auto path encodes the current c2/c4/c8 equality frontier."""

    def args_for(rows: int) -> SimpleNamespace:
        return SimpleNamespace(
            batch_size=rows,
            batch_decode_full_attn_path="auto",
            batch_decode_full_attn_row_chunk_size=0,
            batch_decode_full_attn_row_chunk_layers="",
            batch_decode_full_attn_output_path="batch",
        )

    c2 = args_for(2)
    assert retained_bench._resolved_batch_decode_full_attn_path(c2) == "native_batch"
    assert retained_bench._resolved_batch_decode_full_attn_row_chunk_size(c2) == 0
    assert retained_bench._resolved_batch_decode_full_attn_row_chunk_layers(c2) == ""
    assert retained_bench._resolved_batch_decode_full_attn_output_path(c2) == "batch"

    # c=4/c=8 generated-token equality is green only through the <=2-row
    # full-attention context launch cap. Keep those defaults explicit so future
    # retained-bench refactors do not silently fall back to rows>=4 context
    # launches before the rows>=4 kernel semantics are repaired.
    c4 = args_for(4)
    assert retained_bench._resolved_batch_decode_full_attn_path(c4) == "native_batch"
    assert retained_bench._resolved_batch_decode_full_attn_row_chunk_size(c4) == 2
    assert retained_bench._resolved_batch_decode_full_attn_row_chunk_layers(c4) == "3,15"
    assert retained_bench._resolved_batch_decode_full_attn_output_path(c4) == "batch_gemv"

    c8 = args_for(8)
    assert retained_bench._resolved_batch_decode_full_attn_path(c8) == "native_batch"
    assert retained_bench._resolved_batch_decode_full_attn_row_chunk_size(c8) == 2
    assert retained_bench._resolved_batch_decode_full_attn_row_chunk_layers(c8) == "3,7,11,15,19,23"
    assert retained_bench._resolved_batch_decode_full_attn_output_path(c8) == "batch_gemv"

    c9 = args_for(9)
    assert retained_bench._resolved_batch_decode_full_attn_row_chunk_size(c9) == 0
    assert retained_bench._resolved_batch_decode_full_attn_row_chunk_layers(c9) == ""


