def test_qwen35_batch_equality_matrix_extracts_blocked_retained_equality(tmp_path: Path) -> None:
    artifact_path = tmp_path / "native-equality-c2.json"
    artifact_path.write_text(
        json.dumps(
            {
                "status": "blocked",
                "workload": {
                    "batch_decode_linear_path": "per_row",
                    "batch_decode_full_attention_path": "native_batch",
                    "batch_decode_full_attention_output_path": "batch_gemv",
                    "batch_decode_full_attention_layer_copy": "batch",
                    "batch_decode_full_attention_moe_path": "per_row_c1",
                    "batch_decode_post_attention_path": "batch",
                    "batch_sample_mode": "batched_lm_head",
                    "batch_sample_eq_ok": True,
                    "batch_sample_eq_artifact": "benchmarks/results/sampler-c2.json",
                    "batch_sample_eq_rows": 2,
                    "native_caware_decode": False,
                },
                "performance_claim": False,
                "decision": {"accepted": False, "reason": "missing profiler evidence"},
                "execution": {
                    "batch_execution": {
                        "native_caware_decode": False,
                        "blockers": ["full-attention decode used a per-row fallback"],
                        "decode_execution": {
                            "native_caware_decode": False,
                            "full_attention_decode_path": "native_batch",
                            "full_attention_output_path": "batch_gemv",
                            "post_attention_decode_path": "native_batch",
                            "linear_attention_projection_path": "native_batch",
                            "moe_decode_path": "mixed_grouped_compact_with_per_row_linear_and_full_attention_fallback",
                            "sampler_execution": {
                                "rows": 2,
                                "requested_mode": "batched_lm_head",
                                "mode": "batched_lm_head",
                                "native_row_aware_lm_head": True,
                                "equality_artifact": "benchmarks/results/sampler-c2.json",
                                "equality_rows": 2,
                                "blockers": [],
                            },
                            "blockers": ["linear-attention decode forced to per-row diagnostic path"],
                        },
                    }
                },
                "correctness": {
                    "generated_token_equality": {
                        "passed": True,
                        "prefix_lengths": [137, 137],
                        "first_mismatch_indices": [None, None],
                    }
                },
            }
        ),
        encoding="utf-8",
    )

    summary = equality_matrix._equality_summary(artifact_path)

    assert summary["passed"] is True
    assert summary["retained_ready"] is False
    assert summary["retained_artifact_status"] == "blocked"
    assert summary["performance_claim"] is False
    assert summary["min_equal_prefix_tokens"] == 137
    assert summary["prefix_lengths"] == [137, 137]
    assert summary["workload"]["batch_decode_linear_path"] == "per_row"
    assert summary["workload"]["batch_decode_full_attention_path"] == "native_batch"
    assert summary["workload"]["batch_decode_full_attention_output_path"] == "batch_gemv"
    assert summary["workload"]["batch_sample_mode"] == "batched_lm_head"
    assert summary["workload"]["batch_sample_eq_ok"] is True
    assert summary["workload"]["batch_sample_eq_artifact"] == "benchmarks/results/sampler-c2.json"
    assert summary["workload"]["batch_sample_eq_rows"] == 2
    assert summary["sampler_execution"]["mode"] == "batched_lm_head"
    assert summary["sampler_execution"]["native_row_aware_lm_head"] is True
    assert summary["workload"]["batch_decode_full_attention_layer_copy"] == "batch"
    assert summary["workload"]["batch_decode_full_attention_moe_path"] == "per_row_c1"
    assert summary["workload"]["batch_decode_post_attention_path"] == "batch"
    assert summary["decode_execution"]["full_attention_decode_path"] == "native_batch"
    assert summary["decode_execution"]["full_attention_output_path"] == "batch_gemv"
    assert summary["decode_execution"]["post_attention_decode_path"] == "native_batch"
    assert summary["decode_execution"]["linear_attention_projection_path"] == "native_batch"
    assert summary["retained_blockers"] == [
        "full-attention decode used a per-row fallback",
        "linear-attention decode forced to per-row diagnostic path",
        "missing profiler evidence",
    ]


def test_retained_bench_projection_dispatch_artifact_fails_closed(tmp_path: Path, monkeypatch: pytest.MonkeyPatch) -> None:
    artifact_dir = tmp_path / "benchmarks" / "results"
    artifact_dir.mkdir(parents=True)
    monkeypatch.chdir(tmp_path)

    absolute_path = artifact_dir / "projection-candidates.json"
    absolute_path.write_text(json.dumps({"projection_dispatch_candidates": []}), encoding="utf-8")
    absolute = SimpleNamespace(projection_dispatch_artifact=absolute_path)
    with pytest.raises(ValueError, match="must be a relative path under benchmarks/results"):
        retained_bench._projection_dispatch_candidates_for_payload(absolute)

    traversal = SimpleNamespace(projection_dispatch_artifact=Path("benchmarks/results/../projection-candidates.json"))
    with pytest.raises(ValueError, match="must be a relative path under benchmarks/results"):
        retained_bench._projection_dispatch_candidates_for_payload(traversal)

    monkeypatch.setenv(retained_bench._PROJECTION_DISPATCH_ARTIFACT_ENV, "/tmp/projection-candidates.json")
    from_env = SimpleNamespace(projection_dispatch_artifact=None)
    with pytest.raises(ValueError, match="must be a relative path under benchmarks/results"):
        retained_bench._projection_dispatch_candidates_for_payload(from_env)
    monkeypatch.delenv(retained_bench._PROJECTION_DISPATCH_ARTIFACT_ENV, raising=False)

    missing = SimpleNamespace(projection_dispatch_artifact=Path("benchmarks/results/missing.json"))
    with pytest.raises(ValueError, match="invalid projection dispatch artifact"):
        retained_bench._projection_dispatch_candidates_for_payload(missing)

    directory_path = artifact_dir / "directory.json"
    directory_path.mkdir()
    directory = SimpleNamespace(projection_dispatch_artifact=Path("benchmarks/results/directory.json"))
    with pytest.raises(ValueError, match="must point to a regular JSON artifact"):
        retained_bench._projection_dispatch_candidates_for_payload(directory)

    if hasattr(os, "symlink"):
        symlink_target = artifact_dir / "symlink-target.json"
        symlink_target.write_text(json.dumps({"projection_dispatch_candidates": []}), encoding="utf-8")
        symlink_path = artifact_dir / "symlink.json"
        parent_target = artifact_dir / "parent-target"
        parent_target.mkdir()
        (parent_target / "nested.json").write_text(json.dumps({"projection_dispatch_candidates": []}), encoding="utf-8")
        parent_link = artifact_dir / "parent-link"
        try:
            symlink_path.symlink_to(symlink_target)
            parent_link.symlink_to(parent_target, target_is_directory=True)
        except (OSError, NotImplementedError):
            pass
        else:
            symlink = SimpleNamespace(projection_dispatch_artifact=Path("benchmarks/results/symlink.json"))
            with pytest.raises(ValueError, match="must not be a symlink"):
                retained_bench._projection_dispatch_candidates_for_payload(symlink)
            parent_symlink = SimpleNamespace(
                projection_dispatch_artifact=Path("benchmarks/results/parent-link/nested.json")
            )
            with pytest.raises(ValueError, match="parent directories must not be symlinks"):
                retained_bench._projection_dispatch_candidates_for_payload(parent_symlink)

    no_candidates_path = artifact_dir / "no-candidates.json"
    no_candidates_path.write_text(json.dumps({"status": "accepted"}), encoding="utf-8")
    no_candidates = SimpleNamespace(projection_dispatch_artifact=Path("benchmarks/results/no-candidates.json"))
    with pytest.raises(ValueError, match="must include projection_dispatch_candidates"):
        retained_bench._projection_dispatch_candidates_for_payload(no_candidates)

    malformed_candidate_path = artifact_dir / "malformed-candidate.json"
    malformed_candidate_path.write_text(
        json.dumps({"projection_dispatch_candidates": [{"name": "bad", "selection": {"variant": "row_gemv"}}]}),
        encoding="utf-8",
    )
    malformed_candidate = SimpleNamespace(
        projection_dispatch_artifact=Path("benchmarks/results/malformed-candidate.json")
    )
    with pytest.raises(ValueError, match="invalid projection_dispatch_candidates"):
        retained_bench._projection_dispatch_candidates_for_payload(malformed_candidate)

    candidate_with_missing_evidence = {
        "name": "wmma_caware",
        "selection": {"layer": "linear", "quant": "w4_paro", "variant": "wmma_caware"},
        "min_rows": 2,
        "max_rows": 8,
        "evidence": {
            "artifact_path": "benchmarks/results/projection-missing-evidence.json",
            "aggregate_vs_row_gemv": 1.25,
            "per_request_vs_row_gemv": 1.05,
            "accepted": True,
        },
    }
    missing_evidence_path = artifact_dir / "missing-evidence-candidate.json"
    missing_evidence_path.write_text(
        json.dumps({"projection_dispatch_candidates": [candidate_with_missing_evidence]}),
        encoding="utf-8",
    )
    missing_evidence = SimpleNamespace(
        projection_dispatch_artifact=Path("benchmarks/results/missing-evidence-candidate.json")
    )
    with pytest.raises(ValueError, match="wmma_caware evidence artifact_path must point to an existing JSON artifact"):
        retained_bench._projection_dispatch_candidates_for_payload(missing_evidence)

    (artifact_dir / "projection-wrong-rows-evidence.json").write_text(
        json.dumps(
            _projection_evidence_payload(
                rows=16,
                artifact_path="benchmarks/results/projection-wrong-rows-evidence.json",
                aggregate_vs_row_gemv=1.25,
                per_request_vs_row_gemv=1.05,
            )
        ),
        encoding="utf-8",
    )
    wrong_rows_candidate = json.loads(json.dumps(candidate_with_missing_evidence))
    wrong_rows_candidate["evidence"]["artifact_path"] = "benchmarks/results/projection-wrong-rows-evidence.json"
    wrong_rows_path = artifact_dir / "wrong-rows-evidence-candidate.json"
    wrong_rows_path.write_text(
        json.dumps({"projection_dispatch_candidates": [wrong_rows_candidate]}),
        encoding="utf-8",
    )
    wrong_rows_evidence = SimpleNamespace(
        projection_dispatch_artifact=Path("benchmarks/results/wrong-rows-evidence-candidate.json")
    )
    with pytest.raises(ValueError, match="wmma_caware evidence artifact_path rows must be within candidate row bounds"):
        retained_bench._projection_dispatch_candidates_for_payload(wrong_rows_evidence)

    mismatched_artifact_payload = _projection_evidence_payload(
        rows=2,
        artifact_path="benchmarks/results/projection-stale-artifact-path.json",
        aggregate_vs_row_gemv=1.25,
        per_request_vs_row_gemv=1.05,
    )
    mismatched_artifact_payload["artifact_path"] = "benchmarks/results/projection-stale-other.json"
    (artifact_dir / "projection-stale-artifact-path.json").write_text(
        json.dumps(mismatched_artifact_payload),
        encoding="utf-8",
    )
    stale_artifact_candidate = json.loads(json.dumps(candidate_with_missing_evidence))
    stale_artifact_candidate["evidence"]["artifact_path"] = "benchmarks/results/projection-stale-artifact-path.json"
    stale_artifact_path = artifact_dir / "stale-artifact-path-candidate.json"
    stale_artifact_path.write_text(
        json.dumps({"projection_dispatch_candidates": [stale_artifact_candidate]}),
        encoding="utf-8",
    )
    stale_artifact = SimpleNamespace(
        projection_dispatch_artifact=Path("benchmarks/results/stale-artifact-path-candidate.json")
    )
    with pytest.raises(
        ValueError,
        match="wmma_caware evidence artifact_path evidence.artifact_path must match projection_dispatch.evidence.artifact_path",
    ):
        retained_bench._projection_dispatch_candidates_for_payload(stale_artifact)

    mismatched_source_payload = _projection_evidence_payload(
        rows=2,
        artifact_path="benchmarks/results/projection-stale-source-path.json",
        aggregate_vs_row_gemv=1.25,
        per_request_vs_row_gemv=1.05,
    )
    mismatched_source_payload["source_artifact_path"] = "benchmarks/results/projection-stale-other.json"
    (artifact_dir / "projection-stale-source-path.json").write_text(
        json.dumps(mismatched_source_payload),
        encoding="utf-8",
    )
    stale_source_candidate = json.loads(json.dumps(candidate_with_missing_evidence))
    stale_source_candidate["evidence"]["artifact_path"] = "benchmarks/results/projection-stale-source-path.json"
    stale_source_path = artifact_dir / "stale-source-path-candidate.json"
    stale_source_path.write_text(
        json.dumps({"projection_dispatch_candidates": [stale_source_candidate]}),
        encoding="utf-8",
    )
    stale_source = SimpleNamespace(
        projection_dispatch_artifact=Path("benchmarks/results/stale-source-path-candidate.json")
    )
    with pytest.raises(
        ValueError,
        match="wmma_caware evidence artifact_path evidence.source_artifact_path must match projection_dispatch.evidence.artifact_path",
    ):
        retained_bench._projection_dispatch_candidates_for_payload(stale_source)


def test_batch_c_sweep_rejects_wrong_seed_before_creating_artifacts(tmp_path: Path, monkeypatch) -> None:
    output_dir = tmp_path / "artifacts"
    args = build_c_sweep_parser().parse_args(
        [
            "--dry-run",
            "--batch-sizes",
            "2",
            "--seed",
            "999",
            "--output-dir",
            str(output_dir),
        ]
    )
    monkeypatch.setattr(
        c_sweep.subprocess,
        "run",
        lambda *args, **kwargs: pytest.fail("wrong-seed sweep should fail before launching subprocesses"),
    )

    with pytest.raises(ValueError, match="--seed must be typed int 1234"):
        run_sweep(args)

    assert not output_dir.exists()

    typed_args = build_c_sweep_parser().parse_args(
        ["--dry-run", "--batch-sizes", "2", "--output-dir", str(output_dir)]
    )
    typed_args.seed = 1234.0
    with pytest.raises(ValueError, match="--seed must be typed int 1234"):
        run_sweep(typed_args)

    assert not output_dir.exists()


def test_batch_c_sweep_rejects_invalid_batch_sizes_before_creating_artifacts(tmp_path: Path, monkeypatch) -> None:
    monkeypatch.setattr(
        c_sweep.subprocess,
        "run",
        lambda *args, **kwargs: pytest.fail("invalid batch sizes should fail before launching subprocesses"),
    )
    for bad_text, expected in (
        ("", "batch sizes must be a non-empty string"),
        ("2,", "batch sizes must not contain empty entries"),
        ("2,,4", "batch sizes must not contain empty entries"),
        ("two", "batch sizes must be integers"),
    ):
        with pytest.raises(argparse.ArgumentTypeError, match=expected):
            c_sweep.parse_batch_sizes(bad_text)
    for index, bad_batch_sizes in enumerate(((), (True,), (2.0,), (0,), (2, 2), ["2"])):
        output_dir = tmp_path / f"artifacts-batch-{index}"
        args = build_c_sweep_parser().parse_args(
            ["--dry-run", "--batch-sizes", "2", "--output-dir", str(output_dir)]
        )
        args.batch_sizes = bad_batch_sizes
        with pytest.raises(ValueError, match="--batch-sizes must be a non-empty unique positive-int list"):
            run_sweep(args)
        assert not output_dir.exists()


def test_batch_c_sweep_rejects_invalid_option_bools_before_creating_artifacts(tmp_path: Path, monkeypatch) -> None:
    monkeypatch.setattr(
        c_sweep.subprocess,
        "run",
        lambda *args, **kwargs: pytest.fail("invalid option bools should fail before launching subprocesses"),
    )
    for option, bad_value in (("dry_run", "yes"), ("stop_on_failure", "yes"), ("include_int8", 1), ("include_gguf", 1), ("require_cached_build", "false")):
        output_dir = tmp_path / f"artifacts-{option}"
        args = build_c_sweep_parser().parse_args(
            ["--dry-run", "--batch-sizes", "2", "--output-dir", str(output_dir)]
        )
        setattr(args, option, bad_value)
        flag = "--" + option.replace("_", "-")
        with pytest.raises(ValueError, match=rf"{flag} must be a typed bool"):
            run_sweep(args)
        assert not output_dir.exists()


def test_batch_c_sweep_rejects_unsafe_output_dir_before_creating_artifacts(tmp_path: Path, monkeypatch) -> None:
    output_dir = tmp_path / "artifacts"
    parent_component_output = tmp_path / "output-parent" / ".." / "artifacts"
    symlink_output = tmp_path / "artifacts-link"
    monkeypatch.setattr(
        c_sweep.subprocess,
        "run",
        lambda *args, **kwargs: pytest.fail("unsafe output-dir sweep should fail before launching subprocesses"),
    )

    typed_args = build_c_sweep_parser().parse_args(
        ["--dry-run", "--batch-sizes", "2", "--output-dir", str(output_dir)]
    )
    typed_args.output_dir = None
    with pytest.raises(ValueError, match="--output-dir must be a typed path"):
        run_sweep(typed_args)
    assert not output_dir.exists()

    typed_args.output_dir = ""
    with pytest.raises(ValueError, match="--output-dir must be a non-empty path"):
        run_sweep(typed_args)
    assert not output_dir.exists()

    typed_args.output_dir = "   "
    with pytest.raises(ValueError, match="--output-dir must be a non-empty path"):
        run_sweep(typed_args)
    assert not output_dir.exists()

    for blank_path in ("", "   "):
        with pytest.raises(argparse.ArgumentTypeError, match="path must be non-empty"):
            c_sweep.parse_cli_path(blank_path)

    args = build_c_sweep_parser().parse_args(
        ["--dry-run", "--batch-sizes", "2", "--output-dir", str(parent_component_output)]
    )
    with pytest.raises(ValueError, match="--output-dir must not contain parent-directory components"):
        run_sweep(args)
    assert not (tmp_path / "artifacts").exists()

    output_parent_file = tmp_path / "output-parent-file"
    output_parent_file.write_text("not a directory")
    args = build_c_sweep_parser().parse_args(
        ["--dry-run", "--batch-sizes", "2", "--output-dir", str(output_parent_file / "artifacts")]
    )
    with pytest.raises(ValueError, match="--output-dir parent directories must be directories"):
        run_sweep(args)
    assert output_parent_file.is_file()

    if hasattr(os, "symlink"):
        target = tmp_path / "real-artifacts"
        target.mkdir()
        try:
            symlink_output.symlink_to(target, target_is_directory=True)
        except (OSError, NotImplementedError):
            return
        args = build_c_sweep_parser().parse_args(
            ["--dry-run", "--batch-sizes", "2", "--output-dir", str(symlink_output)]
        )
        with pytest.raises(ValueError, match="--output-dir must not be a symlink"):
            run_sweep(args)


