def test_batch_c_sweep_validate_summary_rejects_unsafe_input_path(tmp_path: Path, capsys) -> None:
    non_object_summary = tmp_path / "summary-list.json"
    non_object_summary.write_text("[]\n")
    assert c_sweep.main(["--validate-summary-json", str(non_object_summary)]) == 1
    captured = capsys.readouterr()
    assert "summary must be an object" in captured.err

    nonfinite_summary = tmp_path / "summary-nonfinite.json"
    nonfinite_summary.write_text('{"bad": NaN}', encoding="utf-8")
    assert c_sweep.main(["--validate-summary-json", str(nonfinite_summary)]) == 1
    captured = capsys.readouterr()
    assert "JSON contains non-finite constant 'NaN'" in captured.err

    parent_component_summary = tmp_path / "summary-parent" / ".." / "summary.json"
    assert c_sweep.main(["--validate-summary-json", str(parent_component_summary)]) == 1
    captured = capsys.readouterr()
    assert "--validate-summary-json must not contain parent-directory components" in captured.err

    summary_parent_file = tmp_path / "summary-parent-file"
    summary_parent_file.write_text("not a directory")
    assert c_sweep.main(["--validate-summary-json", str(summary_parent_file / "summary.json")]) == 1
    captured = capsys.readouterr()
    assert "--validate-summary-json parent directories must be directories" in captured.err

    if hasattr(os, "symlink"):
        target = tmp_path / "summary-real.json"
        target.write_text("{}\n")
        symlink_summary = tmp_path / "summary-link.json"
        try:
            symlink_summary.symlink_to(target)
        except (OSError, NotImplementedError):
            return
        assert c_sweep.main(["--validate-summary-json", str(symlink_summary)]) == 1
        captured = capsys.readouterr()
        assert "--validate-summary-json must not be a symlink" in captured.err

        parent_target = tmp_path / "summary-parent-real"
        parent_link = tmp_path / "summary-parent-link"
        parent_target.mkdir()
        try:
            parent_link.symlink_to(parent_target, target_is_directory=True)
        except (OSError, NotImplementedError):
            return
        assert c_sweep.main(["--validate-summary-json", str(parent_link / "summary.json")]) == 1
        captured = capsys.readouterr()
        assert "--validate-summary-json parent directories must not be symlinks" in captured.err


