def test_batch_c_sweep_primitive_precondition_requires_aa_determinism_fields(tmp_path: Path) -> None:
    primitive_path = tmp_path / "primitive-c2.json"
    command = c_sweep.SweepCommand(
        category="native_diagnostic",
        batch_size=2,
        artifact_path=tmp_path / "native-diagnostic-c2.json",
        argv=(
            "python3",
            "scripts/qwen35_batch_retained_bench.py",
            "--primitive-correctness-json",
            str(primitive_path),
        ),
    )
    primitive_payload = {
        "artifact_path": str(primitive_path),
        "schema": 1,
        "seed": 1234,
        "rows": 2,
        "block_size": 256,
        "max_context_len": 4,
        "num_q_heads": 4,
        "num_kv_heads": 1,
        "head_dim": 8,
        "context_lens": [1, 2],
        "passed": True,
        "append_key_mismatch": 0,
        "append_value_mismatch": 0,
        "attn_batch_vs_c1_max_abs": 0.0,
        "attn_batch_vs_numpy_max_abs": 5.0e-8,
    }
    primitive_path.write_text(json.dumps(primitive_payload))
    missing_aa_fields = c_sweep._primitive_correctness_precondition(command)
    primitive_payload.update(
        {
            "append_batch_aa_key_mismatch": 1,
            "append_batch_aa_value_mismatch": 0,
            "attn_batch_aa_max_abs": 0.0,
            "aa_passed": True,
        }
    )
    primitive_path.write_text(json.dumps(primitive_payload))
    mismatched_append_aa = c_sweep._primitive_correctness_precondition(command)
    primitive_payload.update(
        {
            "append_batch_aa_key_mismatch": 0,
            "attn_batch_aa_max_abs": 1e-8,
            "aa_passed": False,
        }
    )
    primitive_path.write_text(json.dumps(primitive_payload))
    mismatched_attn_aa = c_sweep._primitive_correctness_precondition(command)
    primitive_payload.update(
        {
            "attn_batch_aa_max_abs": 0.0,
            "aa_passed": True,
            "device": _c_sweep_primitive_device_metadata(),
        }
    )
    primitive_path.write_text(json.dumps(primitive_payload))
    passed = c_sweep._primitive_correctness_precondition(command)

    assert missing_aa_fields["passed"] is False
    assert "append_batch_aa_key_mismatch is missing or not integer zero" in missing_aa_fields["reason"]
    assert "attn_batch_aa_max_abs is missing or not 0.0" in missing_aa_fields["reason"]
    assert mismatched_append_aa["passed"] is False
    assert "append_batch_aa_key_mismatch is missing or not integer zero" in mismatched_append_aa["reason"]
    assert mismatched_attn_aa["passed"] is False
    assert "attn_batch_aa_max_abs is missing or not 0.0" in mismatched_attn_aa["reason"]
    assert "aa_passed is not true" in mismatched_attn_aa["reason"]
    assert passed["passed"] is True
    assert passed["append_batch_aa_key_mismatch"] == 0
    assert passed["append_batch_aa_value_mismatch"] == 0
    assert passed["attn_batch_aa_max_abs"] == 0.0
    assert passed["aa_passed"] is True


def test_batch_c_sweep_primitive_precondition_requires_numpy_oracle(tmp_path: Path) -> None:
    primitive_path = tmp_path / "primitive-c2.json"
    command = c_sweep.SweepCommand(
        category="native_diagnostic",
        batch_size=2,
        artifact_path=tmp_path / "native-diagnostic-c2.json",
        argv=(
            "python3",
            "scripts/qwen35_batch_retained_bench.py",
            "--primitive-correctness-json",
            str(primitive_path),
        ),
    )
    primitive_payload = {
        "artifact_path": str(primitive_path),
        "schema": 1,
        "seed": 1234,
        "rows": 2,
        "block_size": 256,
        "max_context_len": 4,
        "num_q_heads": 4,
        "num_kv_heads": 1,
        "head_dim": 8,
        "context_lens": [1, 2],
        "passed": True,
        "append_key_mismatch": 0,
        "append_value_mismatch": 0,
        "attn_batch_vs_c1_max_abs": 0.0,
    }
    primitive_path.write_text(json.dumps(primitive_payload))
    missing_numpy = c_sweep._primitive_correctness_precondition(command)
    primitive_payload["attn_batch_vs_numpy_max_abs"] = 1e-3
    primitive_path.write_text(json.dumps(primitive_payload))
    high_numpy = c_sweep._primitive_correctness_precondition(command)
    primitive_payload["attn_batch_vs_numpy_max_abs"] = math.nan
    primitive_path.write_text(json.dumps(primitive_payload))
    nan_numpy = c_sweep._primitive_correctness_precondition(command)
    primitive_payload["attn_batch_vs_numpy_max_abs"] = -1e-8
    primitive_path.write_text(json.dumps(primitive_payload))
    negative_numpy = c_sweep._primitive_correctness_precondition(command)

    expected_reason = "attn_batch_vs_numpy_max_abs is missing, non-finite, negative, or above 2e-5"
    assert missing_numpy == {
        "kind": "primitive_correctness",
        "artifact_path": str(primitive_path),
        "passed": False,
        "reason": expected_reason,
    }
    assert high_numpy == {
        "kind": "primitive_correctness",
        "artifact_path": str(primitive_path),
        "passed": False,
        "reason": expected_reason,
    }
    assert nan_numpy == {
        "kind": "primitive_correctness",
        "artifact_path": str(primitive_path),
        "passed": False,
        "reason": "primitive correctness artifact is invalid JSON: ValueError: JSON contains non-finite constant 'NaN'",
    }
    assert negative_numpy == {
        "kind": "primitive_correctness",
        "artifact_path": str(primitive_path),
        "passed": False,
        "reason": expected_reason,
    }


def test_batch_c_sweep_primitive_precondition_requires_device_metadata(tmp_path: Path) -> None:
    primitive_path = tmp_path / "primitive-c2.json"
    command = c_sweep.SweepCommand(
        category="native_diagnostic",
        batch_size=2,
        artifact_path=tmp_path / "native-diagnostic-c2.json",
        argv=(
            "python3",
            "scripts/qwen35_batch_retained_bench.py",
            "--primitive-correctness-json",
            str(primitive_path),
        ),
    )
    primitive_payload = {
        "artifact_path": str(primitive_path),
        "schema": 1,
        "seed": 1234,
        "rows": 2,
        "block_size": 256,
        "max_context_len": 4,
        "num_q_heads": 4,
        "num_kv_heads": 1,
        "head_dim": 8,
        "context_lens": [1, 2],
        "passed": True,
        "append_key_mismatch": 0,
        "append_value_mismatch": 0,
        "append_batch_aa_key_mismatch": 0,
        "append_batch_aa_value_mismatch": 0,
        "attn_batch_vs_c1_max_abs": 0.0,
        "attn_batch_vs_numpy_max_abs": 5.0e-8,
        "attn_batch_aa_max_abs": 0.0,
        "aa_passed": True,
    }
    primitive_path.write_text(json.dumps(primitive_payload))
    missing_device = c_sweep._primitive_correctness_precondition(command)
    primitive_payload["device"] = {"env": {"HIP_VISIBLE_DEVICES": ""}}
    primitive_path.write_text(json.dumps(primitive_payload))
    malformed_device = c_sweep._primitive_correctness_precondition(command)
    primitive_payload["device"] = {"env": []}
    primitive_path.write_text(json.dumps(primitive_payload))
    malformed_env = c_sweep._primitive_correctness_precondition(command)
    primitive_payload["device"] = _c_sweep_primitive_device_metadata()
    primitive_payload["device"]["extra_device_field"] = "unexpected"
    primitive_path.write_text(json.dumps(primitive_payload))
    extra_device_key = c_sweep._primitive_correctness_precondition(command)
    primitive_payload["device"] = _c_sweep_primitive_device_metadata()
    primitive_payload["device"]["env"]["OTHER_VISIBLE_DEVICES"] = "1"
    primitive_path.write_text(json.dumps(primitive_payload))
    extra_env_key = c_sweep._primitive_correctness_precondition(command)
    primitive_payload["device"] = _c_sweep_primitive_device_metadata()
    primitive_path.write_text(json.dumps(primitive_payload))
    passed = c_sweep._primitive_correctness_precondition(command)

    assert missing_device == {
        "kind": "primitive_correctness",
        "artifact_path": str(primitive_path),
        "passed": False,
        "reason": "device metadata is missing or not a plain object",
    }
    assert malformed_device["passed"] is False
    assert "device.env.HIP_VISIBLE_DEVICES is not a non-empty string when present" in malformed_device["reason"]
    assert "device.visible_device_count is missing or not a positive int" in malformed_device["reason"]
    assert malformed_env["passed"] is False
    assert "device.env is missing or not a plain object" in malformed_env["reason"]
    assert extra_device_key["passed"] is False
    assert "device metadata contains unknown keys" in extra_device_key["reason"]
    assert extra_env_key["passed"] is False
    assert "device.env contains unknown keys" in extra_env_key["reason"]
    assert passed["passed"] is True
    assert passed["primitive_device"] == _c_sweep_primitive_device_metadata()


def test_batch_c_sweep_skips_retained_when_scaling_reference_shape_missing(
    tmp_path: Path,
    monkeypatch,
) -> None:
    output_dir = tmp_path / "artifacts"
    output_dir.mkdir()
    _write_c_sweep_primitive_summary(output_dir)
    _write_c_sweep_profiler_summary(output_dir, warmup_decode_tokens=1, max_layers=3)
    (output_dir / "native-baseline-c1.json").write_text(
        json.dumps(
            {
                "artifact_path": str(output_dir / "native-baseline-c1.json"),
                "schema": 1,
                "throughput": {"warmed_decode_tok_s": 10.0},
            }
        )
    )
    (output_dir / "serial-bridge-c2.json").write_text(
        json.dumps(
            {
                "artifact_path": str(output_dir / "serial-bridge-c2.json"),
                "schema": 2,
                "status": "blocked",
                "workload": {"concurrency": 2, "prompt_tokens_per_request": 16, "gen_tokens_per_request": 2},
                "measurements": {"decode_tok_s_aggregate": 20.0, "decode_tok_s_per_request": 10.0},
            }
        )
    )
    args = build_c_sweep_parser().parse_args(
        [
            "--batch-sizes",
            "2",
            "--output-dir",
            str(output_dir),
            "--model",
            "/tmp/model",
            "--fixture",
            "/tmp/fixture.json",
            "--prompt-length",
            "16",
            "--decode-tokens",
            "2",
            "--warmup-decode-tokens",
            "1",
            "--max-layers",
            "3",
        ]
    )
    monkeypatch.setattr(c_sweep, "_git_state", lambda: {"commit": "test", "dirty": False, "status_short": []})

    class FakeProc:
        returncode = 0
        stdout = "ok"

    monkeypatch.setattr(c_sweep.subprocess, "run", lambda *args, **kwargs: FakeProc())

    summary = run_sweep(args)

    assert summary["status"] == "blocked"
    assert summary["status_counts"] == {"passed": 2, "skipped": 1}
    skipped = summary["commands"][-1]
    assert skipped["status"] == "skipped"
    assert skipped["precondition"]["kind"] == "c1_baseline"
    assert skipped["precondition"]["reason"] == "prompt token count label is missing; decode token count label is missing"
    assert summary["retained_precondition_counts"] == {
        "primitive_correctness": {"passed": 1},
        "c1_baseline": {"failed": 1},
        "serial_bridge": {"passed": 1},
        "profiler_summary": {"passed": 1},
    }


