def test_hidden_bisect_current_source_rollup_promotes_failures() -> None:
    def stage_summary(stage: str, *, passed: bool, max_abs: float, bit_mismatch: int = 0) -> tuple[str, dict[str, object]]:
        return (
            stage,
            {
                "rows": [
                    {
                        "row": 0,
                        "passed": passed,
                        "comparison_kind": "fp16_bits",
                        "hidden_comparison": {
                            "max_abs": max_abs,
                            "max_abs_flat_index": 1269,
                            "max_abs_index": [0, 1269],
                            "elements_over_atol": 0 if passed else 1,
                            "bit_mismatch": bit_mismatch,
                        },
                    }
                ]
            },
        )

    linear_input_row = {
        "row": 0,
        "passed": True,
        "hidden_comparison": {
            "max_abs": 0.000244140625,
            "max_abs_flat_index": 1269,
            "max_abs_index": [0, 1269],
            "elements_over_atol": 0,
            "bit_mismatch": 7,
        },
    }

    layer_summaries = [
        {
            "layer_limit": 8,
            "decode_linear_inputs": {
                "steps": [
                    {
                        "decode_step": 0,
                        "layers": [
                            {
                                "layer_index": 3,
                                "rows": [linear_input_row],
                            }
                        ],
                    }
                ]
            },
            "decode_full_attention": {
                "steps": [
                    {
                        "decode_step": 0,
                        "layers": [
                            {
                                "layer_index": 2,
                                "stages": dict([stage_summary("output", passed=True, max_abs=0.0)]),
                            },
                            {
                                "layer_index": 3,
                                "stages": dict(
                                    [
                                        stage_summary("input", passed=True, max_abs=0.0, bit_mismatch=3),
                                        stage_summary(
                                            "attn_input_pre_qkv",
                                            passed=False,
                                            max_abs=0.015625,
                                            bit_mismatch=4,
                                        ),
                                        stage_summary(
                                            "q_proj_key_after_project",
                                            passed=False,
                                            max_abs=0.0078125,
                                            bit_mismatch=2,
                                        ),
                                        stage_summary("key_raw_after_cast", passed=True, max_abs=0.0),
                                        stage_summary(
                                            "key_after_prepare",
                                            passed=False,
                                            max_abs=0.005859375,
                                            bit_mismatch=1,
                                        ),
                                    ]
                                ),
                            }
                        ],
                    }
                ]
            },
            "decode_full_kv_samples": {
                "current_source_passed": False,
                "current_source_failure_summary": {
                    "failed_kinds": ["key"],
                    "failed_kind_count": 1,
                    "first_failure": None,
                    "kinds": {
                        "key": {
                            "passed": False,
                            "failure_rows": [0],
                            "failure_row_count": 1,
                            "failed_checks": ["batch_source_vs_c1_source"],
                            "first_failure": {
                                "decode_step": 0,
                                "generated_index": 1,
                                "layer_index": 3,
                                "row": 0,
                                "kind": "key",
                                "check": "batch_source_vs_c1_source",
                                "source_stage": "key_after_prepare",
                                "sample_index": 4,
                                "sample_label": "current",
                                "sample_position": 512,
                                "max_abs": 0.015625,
                                "bit_mismatch": 122,
                            },
                        },
                        "value": {
                            "passed": True,
                            "failure_rows": [],
                            "failure_row_count": 0,
                            "failed_checks": [],
                            "first_failure": None,
                        },
                    },
                },
            },
        }
    ]

    rollup = _decode_full_kv_current_source_rollup(layer_summaries)

    assert rollup["failed_kinds"] == ["key"]
    assert rollup["first_failure"]["layer_limit"] == 8
    assert rollup["first_failure"]["source_stage"] == "key_after_prepare"
    assert rollup["first_failure"]["bit_mismatch"] == 122
    producer_context = rollup["first_failure"]["producer_stage_context"]
    assert producer_context["source_stage"] == "key_after_prepare"
    assert producer_context["first_failed_stage"]["stage"] == "attn_input_pre_qkv"
    assert producer_context["first_failed_stage"]["max_abs"] == 0.015625
    assert producer_context["first_bit_mismatch_stage"]["stage"] == "input"
    assert producer_context["first_bit_mismatch_stage"]["bit_mismatch"] == 3
    assert producer_context["source_stage_record"]["stage"] == "key_after_prepare"
    assert producer_context["source_stage_record"]["passed"] is False
    assert producer_context["source_stage_record"]["bit_mismatch"] == 1
    assert producer_context["current_source_bit_mismatch"] == 122
    assert [record["stage"] for record in producer_context["stages"]] == [
        "input",
        "attn_input_pre_qkv",
        "q_proj_key_after_project",
        "key_raw_after_cast",
        "key_after_prepare",
    ]
    assert rollup["kinds"]["key"]["failed_checks"] == ["batch_source_vs_c1_source"]
    assert rollup["kinds"]["value"]["passed"] is True
    assert rollup["layer_limits"] == [{"layer_limit": 8, "passed": False, "failed_kinds": ["key"]}]

    bit_rollup = _decode_full_attention_bit_drift_rollup(layer_summaries)
    assert bit_rollup["drift_stages"] == [
        "input",
        "attn_input_pre_qkv",
        "q_proj_key_after_project",
        "key_after_prepare",
    ]
    assert bit_rollup["first_bit_drift"]["stage"] == "input"
    assert bit_rollup["first_bit_drift"]["passed_under_atol"] is True
    assert bit_rollup["stages"]["input"] == {
        "passed": False,
        "bit_drift_rows": [0],
        "bit_drift_row_count": 1,
        "total_bit_mismatch": 3,
        "first_bit_drift": bit_rollup["first_bit_drift"],
    }
    assert bit_rollup["layer_limits"] == [
        {
            "layer_limit": 8,
            "drift_stages": [
                "input",
                "attn_input_pre_qkv",
                "q_proj_key_after_project",
                "key_after_prepare",
            ],
        }
    ]

    linear_bit_rollup = _decode_linear_input_bit_drift_rollup(layer_summaries)
    assert linear_bit_rollup["drift_layers"] == [3]
    linear_first = linear_bit_rollup["first_bit_drift"]
    assert {key: linear_first[key] for key in linear_first if key != "producer_context"} == {
        "layer_limit": 8,
        "decode_step": 0,
        "generated_index": 1,
        "layer_index": 3,
        "row": 0,
        "passed_under_atol": True,
        "bit_mismatch": 7,
        "max_abs": 0.000244140625,
        "max_abs_flat_index": 1269,
        "max_abs_index": [0, 1269],
        "elements_over_atol": 0,
    }
    producer_context = linear_first["producer_context"]
    assert producer_context["available"] is True
    assert producer_context["producer_kind"] == "decode_full_attention"
    assert producer_context["producer_layer_index"] == 2
    assert producer_context["target_layer_index"] == 3
    assert producer_context["producer_full_attention"]["layer_index"] == 2
    assert list(producer_context["producer_full_attention"]["stages"]) == ["output"]
    assert linear_bit_rollup["first_handoff"] == {
        "layer_limit": 8,
        "decode_step": 0,
        "generated_index": 1,
        "row": 0,
        "target_layer_index": 3,
        "producer_layer_index": 2,
        "producer_available": True,
        "producer_kind": "decode_full_attention",
        "producer_reason": None,
        "bit_mismatch": 7,
        "passed_under_atol": True,
        "max_abs": 0.000244140625,
        "max_abs_flat_index": 1269,
        "max_abs_index": [0, 1269],
        "elements_over_atol": 0,
    }
    assert linear_bit_rollup["layers"]["3"] == {
        "passed": False,
        "bit_drift_rows": [0],
        "bit_drift_row_count": 1,
        "total_bit_mismatch": 7,
        "first_bit_drift": linear_bit_rollup["first_bit_drift"],
    }
    assert linear_bit_rollup["layer_limits"] == [{"layer_limit": 8, "drift_layers": [3]}]


def test_hidden_bisect_linear_stage_summary_rolls_up_first_bit_drift() -> None:
    def fp16_bits(values: list[list[float]]) -> np.ndarray:
        return np.asarray(values, dtype=np.float16).view(np.uint16)

    batch = HiddenRun(
        seed_tokens=[],
        generated_tokens=[],
        hidden_bits_by_step=[],
        decode_linear_stages_by_step=[
            {
                0: {
                    "attn_input": fp16_bits([[1.0, 2.0]]),
                    "qkv": fp16_bits([[3.0, 4.0]]),
                    "conv_out": np.asarray([[5.0, 6.0]], dtype=np.float32),
                }
            }
        ],
    )
    c1 = HiddenRun(
        seed_tokens=[],
        generated_tokens=[],
        hidden_bits_by_step=[],
        decode_linear_stages_by_step=[
            {
                0: {
                    "attn_input": fp16_bits([[1.0, 2.0]]),
                    "qkv": fp16_bits([[3.0, 4.00390625]]),
                    "conv_out": np.asarray([[5.0, 6.25]], dtype=np.float32),
                }
            }
        ],
    )

    summary = _decode_linear_stage_summary(batch, c1, atol=0.004)

    assert summary is not None
    assert summary["passed"] is False
    assert summary["stage_passed"]["attn_input"] is True
    assert summary["stage_passed"]["qkv"] is True
    assert summary["stage_passed"]["conv_out"] is False
    assert summary["first_bit_drift"] == {
        "decode_step": 0,
        "generated_index": 1,
        "layer_index": 0,
        "stage": "qkv",
        "row": 0,
        "comparison_kind": "fp16_bits",
        "passed_under_atol": True,
        "bit_mismatch": 1,
        "max_abs": 0.00390625,
        "max_abs_flat_index": 1,
        "max_abs_index": [0, 1],
        "elements_over_atol": 0,
    }
    assert summary["first_mismatch"]["stage"] == "conv_out"
    assert summary["first_mismatch"]["comparison_kind"] == "fp32"

    rollup = _decode_linear_stage_bit_drift_rollup([{"layer_limit": 8, "decode_linear_stages": summary}])
    assert rollup["drift_stages"] == ["qkv", "conv_out"]
    assert rollup["first_bit_drift"]["layer_limit"] == 8
    assert rollup["first_bit_drift"]["stage"] == "qkv"
    assert rollup["stages"]["qkv"]["bit_drift_rows"] == [0]
    assert rollup["stages"]["conv_out"]["first_bit_drift"]["comparison_kind"] == "fp32"

    projection_rollup = _decode_linear_projection_bit_drift_rollup(
        [{"layer_limit": 8, "decode_linear_stages": summary}]
    )
    assert projection_rollup["projection_stages"] == ["qkv", "z"]
    assert projection_rollup["bit_exact"] is False
    assert projection_rollup["passed_under_atol"] is True
    assert projection_rollup["drift_stages"] == ["qkv"]
    assert projection_rollup["under_atol_drift_stages"] == ["qkv"]
    assert projection_rollup["over_atol_drift_stages"] == []
    assert projection_rollup["first_bit_drift"]["stage"] == "qkv"
    assert projection_rollup["first_over_atol_drift"] is None
    assert projection_rollup["first_over_atol_layer_limit"] is None
    assert projection_rollup["stages"]["qkv"]["total_bit_mismatch"] == 1
    assert projection_rollup["stages"]["qkv"]["total_elements_over_atol"] == 0
    assert projection_rollup["stages"]["qkv"]["first_over_atol_drift"] is None
    assert projection_rollup["stages"]["z"]["bit_exact"] is True
    assert projection_rollup["layer_limits"] == [
        {
            "layer_limit": 8,
            "drift_stages": ["qkv"],
            "drift_stage_count": 1,
            "under_atol_drift_stages": ["qkv"],
            "under_atol_drift_stage_count": 1,
            "over_atol_drift_stages": [],
            "over_atol_drift_stage_count": 0,
            "first_over_atol_drift": None,
        }
    ]


