def test_hidden_bisect_full_kv_sample_positions_cover_page_boundaries() -> None:
    assert _decode_full_kv_sample_positions(512, block_size=256) == (0, 255, 256, 511, 512)
    assert _decode_full_kv_sample_positions(2, block_size=256) == (0, 2, 2, 1, 2)


def test_hidden_bisect_trace_array_to_f32_uses_fp16_for_uint16_traces() -> None:
    bits = np.array([[0x3C00, 0x4000, 0xC000]], dtype=np.uint16)

    values = _trace_array_to_f32(bits)

    np.testing.assert_allclose(values, np.array([[1.0, 2.0, -2.0]], dtype=np.float32))


def test_hidden_bisect_full_attention_focus_indices_skip_narrow_trace_stages() -> None:
    wide = np.array([[0x3C00, 0x4000, 0x4200, 0x4400]], dtype=np.uint16)
    narrow = np.array([[0x3C00, 0x4000]], dtype=np.uint16)
    run = HiddenRun(
        seed_tokens=[1],
        generated_tokens=[[2]],
        hidden_bits_by_step=[wide],
        decode_full_attention_by_step=[{0: {"input": wide, "value_after_project": narrow}}],
    )

    summary = _decode_full_attention_summary(run, run, atol=0.0, focus_hidden_flat_indices=(3,))

    assert summary is not None
    input_comparison = summary["steps"][0]["layers"][0]["stages"]["input"]["rows"][0]["hidden_comparison"]
    narrow_comparison = summary["steps"][0]["layers"][0]["stages"]["value_after_project"]["rows"][0]["hidden_comparison"]
    assert input_comparison["selected_abs_diffs"][0]["flat_index"] == 3
    assert "selected_abs_diffs" not in narrow_comparison


def test_hidden_bisect_full_context_oracle_prefers_immediate_query_trace(monkeypatch: pytest.MonkeyPatch) -> None:
    def bf16_bits(values: np.ndarray) -> np.ndarray:
        return (np.asarray(values, dtype=np.float32).view(np.uint32) >> np.uint32(16)).astype(np.uint16)

    key_bits = bf16_bits(np.array([[[1.0, 0.0]], [[0.0, 1.0]]], dtype=np.float32))
    value_bits = bf16_bits(np.array([[[2.0, 4.0]], [[8.0, 16.0]]], dtype=np.float32))

    def fake_kv_prefix(*_args, **_kwargs):
        return key_bits, value_bits

    monkeypatch.setattr("scripts.qwen35_batch_hidden_bisect._copy_decode_full_kv_prefix_bits", fake_kv_prefix)
    session = SimpleNamespace(config=SimpleNamespace(num_attention_heads=1, head_dim=2))
    immediate_query = np.array([[1.0, 0.0]], dtype=np.float32)
    late_query = np.array([[0.0, 1.0]], dtype=np.float32)

    oracle = _decode_full_context_oracles_from_trace(
        session,
        {
            3: {
                "query": late_query,
                "query_after_prepare": immediate_query,
                "attn_context": np.zeros((1, 2), dtype=np.float32),
            }
        },
        rows=1,
        positions=(1,),
        slots=(0,),
    )

    expected = _numpy_full_attention_context_row(
        immediate_query.reshape(1, 2),
        key_bits,
        value_bits,
        scale=float(2 ** -0.5),
    ).reshape(1, 2)
    late_expected = _numpy_full_attention_context_row(
        late_query.reshape(1, 2),
        key_bits,
        value_bits,
        scale=float(2 ** -0.5),
    ).reshape(1, 2)
    assert oracle[3]["query_source"] == "query_after_prepare"
    assert oracle[3]["key_prefix_hashes"].shape == (1, 2)
    assert oracle[3]["value_prefix_hashes"].shape == (1, 2)
    assert oracle[3]["key_prefix_hashes"][0, 0] != oracle[3]["key_prefix_hashes"][0, 1]
    np.testing.assert_allclose(oracle[3]["context"], expected)
    assert not np.allclose(oracle[3]["context"], late_expected)


