def test_resident_scheduler_sampler_states_track_generated_history() -> None:
    scheduler = ResidentBatchScheduler(capacity=2, context_bucket_size=4)
    r0 = scheduler.submit(
        [10, 11],
        max_new_tokens=3,
        sampling=PerRowSamplingParams(temperature=0.7, seed=123),
        sampling_row_index=0,
    )
    r1 = scheduler.submit(
        [20],
        max_new_tokens=3,
        sampling=PerRowSamplingParams(temperature=0.8, seed=123),
        sampling_row_index=1,
    )
    scheduler.admit_pending()

    state0 = scheduler.sampler_state(r0)
    state1 = scheduler.sampler_state(r1)
    assert state0.prompt_tokens == (10, 11)
    assert state0.request_id == r0
    assert state0.row_index == 0
    assert state0.generated_tokens == []
    assert state0.step_index == 0
    assert state1.row_index == 1
    assert state0.seed != state1.seed

    forward = scheduler.sampler_params_block((r0, r1))
    reverse = scheduler.sampler_params_block((r1, r0))
    assert forward.seeds == (state0.seed, state1.seed)
    assert reverse.seeds == (state1.seed, state0.seed)
    assert scheduler.sampler_states_block((r1, r0)) == (state1, state0)

    scheduler.record_generated([GeneratedToken(r0, 100), GeneratedToken(r1, 200)])
    assert state0.generated_tokens == [100]
    assert state0.history_tokens == (10, 11, 100)
    assert state0.step_index == 1
    assert state1.generated_tokens == [200]
    assert state1.history_tokens == (20, 200)
    assert state1.step_index == 1

    scheduler.record_generated([GeneratedToken(r0, 101, finished=True)])
    with pytest.raises(KeyError, match="sampler state"):
        scheduler.sampler_state(r0)
    assert scheduler.sampler_state(r1).generated_tokens == [200]


def test_resident_scheduler_record_generated_events_emit_decode_telemetry() -> None:
    scheduler = ResidentBatchScheduler(capacity=1, context_bucket_size=4)
    request_id = scheduler.submit(
        [10, 11],
        max_new_tokens=2,
        sampling=PerRowSamplingParams(
            temperature=0.7,
            top_k=4,
            logit_bias={7: 0.5},
            forced_tokens_pending=(55, 56),
            forced_token_reason="tool_choice_required",
        ),
        sampling_row_index=3,
    )
    scheduler.admit_pending()
    assert scheduler.next_prefill_work(chunk_size=8) is not None

    events = scheduler.record_generated_events(
        [GeneratedToken(request_id, 55)],
        native_gpu_requested=True,
        execution_path="native_scheduler",
        native_caware_decode=True,
    )

    assert len(events) == 1
    event = events[0]
    assert isinstance(event, GeneratedTokenEvent)
    assert event.request_id == request_id
    assert event.token_id == 55
    assert event.completed is None
    assert event.stream_chunk.text == ""
    assert event.stream_chunk.telemetry is not None
    assert event.stream_chunk.telemetry.to_json_dict()["decode_state"] == {
        "row_index": 3,
        "step_index": 1,
        "prompt_tokens": 2,
        "generated_tokens": 1,
        "phase": "answer",
        "continuation_eligible": False,
        "request_id": str(request_id),
        "answer_tokens": 1,
        "forced_tokens_pending": [55, 56],
        "forced_token_id": 55,
        "forced_token_reason": "tool_choice_required",
        "forced_tokens_remaining": 1,
        "active_processors": ["logit_bias", "forced_tokens_pending"],
        "sampler_fast_path_blockers": ["temperature", "logit_bias", "forced_tokens_pending"],
        "sampler_fallback_reason": "native_gpu_unsupported_request",
        "sampler_mode": "host_logits_sample",
        "full_vocab_logits_d2h": True,
        "execution_path": "native_scheduler",
        "native_caware_decode": True,
    }

    final_events = scheduler.record_generated_events([GeneratedToken(request_id, 56)])

    assert len(final_events) == 1
    assert final_events[0].completed is not None
    assert final_events[0].stream_chunk.finish_details is not None
    assert final_events[0].stream_chunk.finish_details.to_json_dict() == {
        "reason": "length",
        "length_limit": 2,
    }


def test_resident_scheduler_record_generated_events_emit_stop_suffix_telemetry() -> None:
    scheduler = ResidentBatchScheduler(capacity=1, context_bucket_size=4)
    request_id = scheduler.submit(
        [10, 11],
        max_new_tokens=4,
        sampling=PerRowSamplingParams(stop_token_sequences=((55, 56), (55, 57))),
        sampling_row_index=2,
    )
    scheduler.admit_pending()
    assert scheduler.next_prefill_work(chunk_size=8) is not None

    partial_events = scheduler.record_generated_events([GeneratedToken(request_id, 55)])

    partial_state = partial_events[0].stream_chunk.telemetry.to_json_dict()["decode_state"]
    assert partial_state["stop_suffix_state"] == {
        "partial_suffix": [55],
        "candidate_sequences": [[55, 56], [55, 57]],
    }
    assert partial_state["active_processors"] == ["stop_token_sequences"]
    assert partial_state["sampler_fast_path_blockers"] == ["stop_token_sequences"]

    matched_events = scheduler.record_generated_events([GeneratedToken(request_id, 56, finished=True)])

    matched_state = matched_events[0].stream_chunk.telemetry.to_json_dict()["decode_state"]
    assert matched_state["stop_suffix_state"] == {"matched_sequence": [55, 56]}
    assert matched_events[0].stream_chunk.finish_details is not None
    assert matched_events[0].stream_chunk.finish_details.to_json_dict() == {"reason": "stop"}


