def test_qwen35_batch_diagnostic_schema_validates_claimed_generated_token_equality() -> None:
    payload = {
        "status": "blocked",
        "performance_claim": False,
        "workload": {
            "native_compact_prefill": True,
            "native_caware_decode": False,
            "concurrency": 2,
            "prompt_lengths": [2, 2],
            "prompt_tokens_per_request": 2,
            "prompt_tokens_aggregate": 4,
            "warmup_decode_tokens": 0,
            "gen_tokens_per_request": 2,
            "gen_tokens_aggregate": 4,
        },
        "correctness": {
            "passed": False,
            "oracle": "generated-token equality vs independent c=1 resident runs",
            "generated_token_equality": {
                "passed": True,
                "skipped": False,
                "batch_sequences": [[10, 11, 12], [20, 21, 22]],
                "c1_sequences": [[10, 11, 12], [20, 21, 22]],
                "mismatches": [],
            },
        },
        "execution": {
            "seed_tokens": {"0": {"token_id": 10}, "1": {"token_id": 20}},
            "generated_tokens": {"0": [{"token_id": 11}, {"token_id": 12}], "1": [{"token_id": 21}, {"token_id": 22}]},
            "completed": [
                {"request_id": 0, "prompt_tokens": [100, 101], "generated_tokens": [11, 12], "finished": True, "finish_reason": "length"},
                {"request_id": 1, "prompt_tokens": [200, 201], "generated_tokens": [21, 22], "finished": True, "finish_reason": "length"},
            ],
            "batch_execution": {
                "native_compact_prefill": True,
                "native_caware_decode": False,
                "throughput_claim_eligible": False,
            }
        },
        "decision": {"accepted": False},
    }

    validate_cn_diagnostic_artifact_payload(payload)

    warmup_completed_claim = json.loads(json.dumps(payload))
    warmup_completed_claim["workload"]["warmup_decode_tokens"] = 1
    warmup_completed_claim["correctness"]["generated_token_equality"]["batch_sequences"] = [
        [10, 110, 11, 12],
        [20, 210, 21, 22],
    ]
    warmup_completed_claim["correctness"]["generated_token_equality"]["c1_sequences"] = [
        [10, 110, 11, 12],
        [20, 210, 21, 22],
    ]
    warmup_completed_claim["execution"]["completed"][0]["generated_tokens"] = [110, 11, 12]
    warmup_completed_claim["execution"]["completed"][1]["generated_tokens"] = [210, 21, 22]
    validate_cn_diagnostic_artifact_payload(warmup_completed_claim)

    missing_c1 = json.loads(json.dumps(payload))
    missing_c1["correctness"]["generated_token_equality"].pop("c1_sequences")
    with pytest.raises(ValueError, match="c1_sequences must be a list when passed is true"):
        validate_cn_diagnostic_artifact_payload(missing_c1)

    mismatched_c1 = json.loads(json.dumps(payload))
    mismatched_c1["correctness"]["generated_token_equality"]["c1_sequences"][1][2] = 99
    with pytest.raises(ValueError, match="batch_sequences must equal c1_sequences when passed is true"):
        validate_cn_diagnostic_artifact_payload(mismatched_c1)

    skipped_claim = json.loads(json.dumps(payload))
    skipped_claim["correctness"]["generated_token_equality"]["skipped"] = True
    with pytest.raises(ValueError, match="skipped must be false when passed is true"):
        validate_cn_diagnostic_artifact_payload(skipped_claim)

    missing_oracle_claim = json.loads(json.dumps(payload))
    missing_oracle_claim["correctness"].pop("oracle")
    with pytest.raises(ValueError, match="correctness.oracle must name generated-token equality vs independent c=1"):
        validate_cn_diagnostic_artifact_payload(missing_oracle_claim)

    empty_row_claim = json.loads(json.dumps(payload))
    empty_row_claim["correctness"]["generated_token_equality"]["batch_sequences"][0] = []
    empty_row_claim["correctness"]["generated_token_equality"]["c1_sequences"][0] = []
    with pytest.raises(ValueError, match="batch_sequences\\[0\\] must be a non-empty per-row token-id list"):
        validate_cn_diagnostic_artifact_payload(empty_row_claim)

    negative_token_claim = json.loads(json.dumps(payload))
    negative_token_claim["correctness"]["generated_token_equality"]["batch_sequences"][0][2] = -1
    negative_token_claim["correctness"]["generated_token_equality"]["c1_sequences"][0][2] = -1
    with pytest.raises(ValueError, match="batch_sequences\\[0\\] must contain only non-negative token ids"):
        validate_cn_diagnostic_artifact_payload(negative_token_claim)

    mismatched_seed_claim = json.loads(json.dumps(payload))
    mismatched_seed_claim["execution"]["seed_tokens"]["1"]["token_id"] = 99
    with pytest.raises(ValueError, match="execution.seed_tokens.1 must match correctness.generated_token_equality.batch_sequences first token"):
        validate_cn_diagnostic_artifact_payload(mismatched_seed_claim)

    partial_seed_claim = json.loads(json.dumps(payload))
    partial_seed_claim["execution"]["seed_tokens"] = {"0": {"token_id": 10}}
    with pytest.raises(ValueError, match="execution.seed_tokens length must match workload.concurrency"):
        validate_cn_diagnostic_artifact_payload(partial_seed_claim)

    stale_seed_row_claim = json.loads(json.dumps(payload))
    stale_seed_row_claim["execution"]["seed_tokens"] = {"0": {"token_id": 10}, "2": {"token_id": 99}}
    with pytest.raises(ValueError, match="execution.seed_tokens keys must match workload.concurrency row ids"):
        validate_cn_diagnostic_artifact_payload(stale_seed_row_claim)

    all_empty_seed_claim = json.loads(json.dumps(payload))
    all_empty_seed_claim["execution"]["seed_tokens"] = {}
    validate_cn_diagnostic_artifact_payload(all_empty_seed_claim)

    mismatched_generated_claim = json.loads(json.dumps(payload))
    mismatched_generated_claim["execution"]["generated_tokens"]["0"][1]["token_id"] = 99
    with pytest.raises(ValueError, match="execution.generated_tokens.0 must match correctness.generated_token_equality.batch_sequences suffix"):
        validate_cn_diagnostic_artifact_payload(mismatched_generated_claim)

    partial_generated_claim = json.loads(json.dumps(payload))
    partial_generated_claim["execution"]["generated_tokens"]["1"] = []
    with pytest.raises(ValueError, match="execution.generated_tokens.1 must be non-empty when any generated-token metadata is present"):
        validate_cn_diagnostic_artifact_payload(partial_generated_claim)

    extra_generated_row_claim = json.loads(json.dumps(payload))
    extra_generated_row_claim["execution"]["generated_tokens"]["2"] = [{"token_id": 99}]
    with pytest.raises(ValueError, match="execution.generated_tokens keys must match workload.concurrency row ids"):
        validate_cn_diagnostic_artifact_payload(extra_generated_row_claim)

    all_empty_generated_claim = json.loads(json.dumps(payload))
    all_empty_generated_claim["execution"]["generated_tokens"] = {"0": [], "1": []}
    validate_cn_diagnostic_artifact_payload(all_empty_generated_claim)

    absent_generated_claim = json.loads(json.dumps(payload))
    absent_generated_claim["execution"]["generated_tokens"] = {}
    validate_cn_diagnostic_artifact_payload(absent_generated_claim)

    mismatched_completed_claim = json.loads(json.dumps(payload))
    mismatched_completed_claim["execution"]["completed"][1]["generated_tokens"][0] = 99
    with pytest.raises(ValueError, match=r"execution.completed\[1\].generated_tokens must match correctness.generated_token_equality.batch_sequences warmup\+decode suffix"):
        validate_cn_diagnostic_artifact_payload(mismatched_completed_claim)

    missing_completed_generated_claim = json.loads(json.dumps(payload))
    missing_completed_generated_claim["execution"]["completed"][1].pop("generated_tokens")
    with pytest.raises(ValueError, match=r"execution.completed\[1\].generated_tokens must be present"):
        validate_cn_diagnostic_artifact_payload(missing_completed_generated_claim)

    duplicate_completed_claim = json.loads(json.dumps(payload))
    duplicate_completed_claim["execution"]["completed"][1]["request_id"] = 0
    with pytest.raises(ValueError, match="execution.completed request_id values must be unique"):
        validate_cn_diagnostic_artifact_payload(duplicate_completed_claim)

    partial_completed_claim = json.loads(json.dumps(payload))
    partial_completed_claim["execution"]["completed"].pop()
    with pytest.raises(ValueError, match="execution.completed length must match workload.concurrency"):
        validate_cn_diagnostic_artifact_payload(partial_completed_claim)

    extra_completed_claim = json.loads(json.dumps(payload))
    extra_completed_claim["execution"]["completed"].append(json.loads(json.dumps(payload["execution"]["completed"][0])))
    with pytest.raises(ValueError, match="execution.completed length must match workload.concurrency"):
        validate_cn_diagnostic_artifact_payload(extra_completed_claim)

    unfinished_completed_claim = json.loads(json.dumps(payload))
    unfinished_completed_claim["execution"]["completed"][0]["finished"] = False
    with pytest.raises(ValueError, match=r"execution.completed\[0\].finished must be true"):
        validate_cn_diagnostic_artifact_payload(unfinished_completed_claim)

    missing_finish_reason_claim = json.loads(json.dumps(payload))
    missing_finish_reason_claim["execution"]["completed"][0].pop("finish_reason")
    with pytest.raises(ValueError, match=r"execution.completed\[0\].finish_reason must be a non-empty string"):
        validate_cn_diagnostic_artifact_payload(missing_finish_reason_claim)

    blank_finish_reason_claim = json.loads(json.dumps(payload))
    blank_finish_reason_claim["execution"]["completed"][0]["finish_reason"] = " "
    with pytest.raises(ValueError, match=r"execution.completed\[0\].finish_reason must be a non-empty string"):
        validate_cn_diagnostic_artifact_payload(blank_finish_reason_claim)

    mismatched_completed_prompt_claim = json.loads(json.dumps(payload))
    mismatched_completed_prompt_claim["execution"]["completed"][1]["prompt_tokens"].pop()
    with pytest.raises(ValueError, match=r"execution.completed\[1\].prompt_tokens length must match workload.prompt_lengths"):
        validate_cn_diagnostic_artifact_payload(mismatched_completed_prompt_claim)

    partial_completed_prompt_claim = json.loads(json.dumps(payload))
    partial_completed_prompt_claim["execution"]["completed"][1].pop("prompt_tokens")
    with pytest.raises(ValueError, match=r"execution.completed\[1\].prompt_tokens must be present when any completed prompt metadata is present"):
        validate_cn_diagnostic_artifact_payload(partial_completed_prompt_claim)

    missing_completed_prompt_lengths_claim = json.loads(json.dumps(payload))
    missing_completed_prompt_lengths_claim["workload"].pop("prompt_lengths")
    with pytest.raises(ValueError, match="workload.prompt_lengths must be a list when completed prompt metadata is present"):
        validate_cn_diagnostic_artifact_payload(missing_completed_prompt_lengths_claim)

    zero_completed_prompt_lengths_claim = json.loads(json.dumps(payload))
    zero_completed_prompt_lengths_claim["workload"]["prompt_lengths"] = [0, 2]
    zero_completed_prompt_lengths_claim["workload"]["prompt_tokens_per_request"] = None
    zero_completed_prompt_lengths_claim["workload"]["prompt_tokens_aggregate"] = 2
    zero_completed_prompt_lengths_claim["execution"]["completed"][0]["prompt_tokens"] = []
    with pytest.raises(ValueError, match="workload.prompt_lengths entries must be positive ints when completed prompt metadata is present"):
        validate_cn_diagnostic_artifact_payload(zero_completed_prompt_lengths_claim)

    all_absent_completed_prompt_claim = json.loads(json.dumps(payload))
    for completed in all_absent_completed_prompt_claim["execution"]["completed"]:
        completed.pop("prompt_tokens")
    validate_cn_diagnostic_artifact_payload(all_absent_completed_prompt_claim)

    partial_prompt_lengths_claim = json.loads(json.dumps(payload))
    partial_prompt_lengths_claim["workload"]["prompt_lengths"] = [2]
    with pytest.raises(ValueError, match="workload.prompt_lengths length must match workload.concurrency"):
        validate_cn_diagnostic_artifact_payload(partial_prompt_lengths_claim)

    bad_prompt_lengths_claim = json.loads(json.dumps(payload))
    bad_prompt_lengths_claim["workload"]["prompt_lengths"] = [2, 0]
    with pytest.raises(ValueError, match="workload.prompt_lengths entries must be positive ints"):
        validate_cn_diagnostic_artifact_payload(bad_prompt_lengths_claim)

    mismatched_prompt_per_request_claim = json.loads(json.dumps(payload))
    mismatched_prompt_per_request_claim["workload"]["prompt_tokens_per_request"] = 3
    with pytest.raises(ValueError, match="workload.prompt_tokens_per_request must match every workload.prompt_lengths entry"):
        validate_cn_diagnostic_artifact_payload(mismatched_prompt_per_request_claim)

    bad_prompt_per_request_claim = json.loads(json.dumps(payload))
    bad_prompt_per_request_claim["workload"]["prompt_tokens_per_request"] = 0
    with pytest.raises(ValueError, match="workload.prompt_tokens_per_request must be a positive int"):
        validate_cn_diagnostic_artifact_payload(bad_prompt_per_request_claim)

    mismatched_prompt_aggregate_claim = json.loads(json.dumps(payload))
    mismatched_prompt_aggregate_claim["workload"]["prompt_tokens_aggregate"] = 6
    with pytest.raises(ValueError, match="workload.prompt_tokens_aggregate must equal sum"):
        validate_cn_diagnostic_artifact_payload(mismatched_prompt_aggregate_claim)

    bad_prompt_aggregate_claim = json.loads(json.dumps(payload))
    bad_prompt_aggregate_claim["workload"]["prompt_tokens_aggregate"] = -1
    with pytest.raises(ValueError, match="workload.prompt_tokens_aggregate must be a non-negative int"):
        validate_cn_diagnostic_artifact_payload(bad_prompt_aggregate_claim)

    unbacked_prompt_aggregate_claim = json.loads(json.dumps(payload))
    unbacked_prompt_aggregate_claim["workload"].pop("prompt_lengths")
    unbacked_prompt_aggregate_claim["workload"].pop("prompt_tokens_per_request")
    for completed in unbacked_prompt_aggregate_claim["execution"]["completed"]:
        completed.pop("prompt_tokens")
    with pytest.raises(ValueError, match="workload.prompt_tokens_aggregate must be backed by workload.prompt_lengths or workload.prompt_tokens_per_request"):
        validate_cn_diagnostic_artifact_payload(unbacked_prompt_aggregate_claim)

    mismatched_gen_aggregate_claim = json.loads(json.dumps(payload))
    mismatched_gen_aggregate_claim["workload"]["gen_tokens_aggregate"] = 5
    with pytest.raises(ValueError, match="workload.gen_tokens_aggregate must equal workload.concurrency times workload.gen_tokens_per_request"):
        validate_cn_diagnostic_artifact_payload(mismatched_gen_aggregate_claim)

    bad_gen_aggregate_claim = json.loads(json.dumps(payload))
    bad_gen_aggregate_claim["workload"]["gen_tokens_aggregate"] = 0
    with pytest.raises(ValueError, match="workload.gen_tokens_aggregate must be a positive int"):
        validate_cn_diagnostic_artifact_payload(bad_gen_aggregate_claim)

    missing_shape_claim = json.loads(json.dumps(payload))
    missing_shape_claim["workload"].pop("concurrency")
    missing_shape_claim["workload"].pop("warmup_decode_tokens")
    missing_shape_claim["workload"].pop("gen_tokens_per_request")
    with pytest.raises(ValueError, match="workload.concurrency must be an int > 1 when generated_token_equality.passed is true"):
        validate_cn_diagnostic_artifact_payload(missing_shape_claim)


def test_qwen35_retained_payload_json_rejects_nan() -> None:
    with pytest.raises(ValueError, match="Out of range float values"):
        retained_bench._payload_json({"bad": float("nan")})

    assert json.loads(retained_bench._payload_json({"ok": 1.0})) == {"ok": 1.0}


def test_qwen35_retained_load_json_path_rejects_nonfinite(tmp_path: Path) -> None:
    payload_path = tmp_path / "payload.json"
    payload_path.write_text('{"bad": Infinity}', encoding="utf-8")
    with pytest.raises(ValueError, match="JSON contains non-finite constant 'Infinity'"):
        retained_bench._load_json_path(payload_path)

    payload_path.write_text('{"ok": 1.0}', encoding="utf-8")
    assert retained_bench._load_json_path(payload_path) == {"ok": 1.0}


def test_qwen35_retained_scaling_comparison_uses_c1_and_serial_artifacts(tmp_path: Path) -> None:
    c1 = tmp_path / "native-baseline-c1.json"
    c1.write_text(
        json.dumps(
            {
                "artifact_path": str(c1),
                "run_tag": "c1",
                "prompt_length": 512,
                "decode_tokens": 128,
                "throughput": {"warmed_decode_tok_s": 5.0},
            }
        )
    )
    serial = tmp_path / "serial-bridge-c2.json"
    serial.write_text(
        json.dumps(
            {
                "artifact_path": str(serial),
                "run_tag": "serial-c2",
                "status": "blocked",
                "workload": {"concurrency": 2, "prompt_tokens_per_request": 512, "gen_tokens_per_request": 128},
                "measurements": {
                    "decode_tok_s_aggregate": 8.0,
                    "decode_tok_s_per_request": 4.0,
                },
            }
        )
    )
    args = argparse.Namespace(c1_baseline_json=c1, serial_bridge_json=serial)

    scaling = retained_bench._build_scaling_comparison(
        args,
        native_decode_tok_s_aggregate=16.0,
        native_decode_tok_s_per_request=8.0,
    )

    assert scaling["complete"] is True
    assert tuple(scaling["ratios"].keys()) == RETAINED_ARTIFACT_REQUIRED_SCALING_RATIOS
    assert all(baseline_name in scaling for baseline_name in RETAINED_ARTIFACT_REQUIRED_SCALING_BASELINES)
    assert scaling["c1_baseline"]["status"] == "loaded"
    assert scaling["c1_baseline"]["reason"] is None
    assert scaling["c1_baseline"]["reference_artifact_path"] == str(c1)
    assert scaling["c1_baseline"]["workload_concurrency"] == 1
    assert scaling["c1_baseline"]["prompt_tokens_per_request"] == 512
    assert scaling["c1_baseline"]["gen_tokens_per_request"] == 128
    assert scaling["c1_baseline"]["decode_tok_s_aggregate"] == 5.0
    assert scaling["serial_bridge_baseline"]["status"] == "blocked"
    assert scaling["serial_bridge_baseline"]["reason"] is None
    assert scaling["serial_bridge_baseline"]["reference_artifact_path"] == str(serial)
    assert scaling["serial_bridge_baseline"]["workload_concurrency"] == 2
    assert scaling["serial_bridge_baseline"]["prompt_tokens_per_request"] == 512
    assert scaling["serial_bridge_baseline"]["gen_tokens_per_request"] == 128
    assert scaling["serial_bridge_baseline"]["decode_tok_s_per_request"] == 4.0
    assert scaling["ratios"] == {
        "aggregate_vs_c1": 16.0 / 5.0,
        "per_request_vs_c1": 8.0 / 5.0,
        "aggregate_vs_serial_bridge": 2.0,
        "per_request_vs_serial_bridge": 2.0,
    }
    assert retained_bench._scaling_performance_blockers(scaling) == []


def test_qwen35_retained_scaling_performance_blocks_non_winning_aggregate_ratios() -> None:
    scaling = {
        "complete": True,
        "ratios": {
            "aggregate_vs_c1": 0.93,
            "per_request_vs_c1": 0.46,
            "aggregate_vs_serial_bridge": 1.08,
            "per_request_vs_serial_bridge": 1.08,
        },
    }

    blockers = retained_bench._scaling_performance_blockers(scaling)

    assert blockers == ["scaling.ratios.aggregate_vs_c1 must be > 1.0 for retained performance claim"]


