def test_qwen35_retained_scaling_reference_rejects_mismatched_input_labels(
    tmp_path: Path,
    monkeypatch: pytest.MonkeyPatch,
) -> None:
    monkeypatch.delenv("HIP_VISIBLE_DEVICES", raising=False)
    serial = tmp_path / "serial-bridge-c2.json"
    payload = {
        "artifact_path": str(serial),
        "status": "blocked",
        "commands": {
            "benchmark": f"python3 scripts/qwen35_batch_serial_bench.py --model /tmp/model --fixture /tmp/fixture.json --json {serial}"
        },
        "workload": {"concurrency": 2, "prompt_tokens_per_request": 512, "gen_tokens_per_request": 128},
        "measurements": {"decode_tok_s_aggregate": 8.0, "decode_tok_s_per_request": 4.0},
    }
    serial.write_text(json.dumps(payload))
    expected_inputs = {"model": "/tmp/model", "fixture": "/tmp/fixture.json"}
    matched = retained_bench._scaling_reference(serial, expected_inputs=expected_inputs)

    payload["commands"]["benchmark"] = f"python3 scripts/qwen35_batch_serial_bench.py --fixture /tmp/fixture.json --json {serial}"
    serial.write_text(json.dumps(payload))
    missing_model = retained_bench._scaling_reference(serial, expected_inputs=expected_inputs)

    payload["commands"]["benchmark"] = (
        f"python3 scripts/qwen35_batch_serial_bench.py --model /tmp/model --fixture /tmp/other-fixture.json --json {serial}"
    )
    serial.write_text(json.dumps(payload))
    mismatched_fixture = retained_bench._scaling_reference(serial, expected_inputs=expected_inputs)

    assert matched["reason"] is None
    assert matched["decode_tok_s_aggregate"] == 8.0
    assert missing_model["reason"] == "commands.benchmark must include --model matching retained model"
    assert missing_model["decode_tok_s_aggregate"] is None
    assert mismatched_fixture["reason"] == "commands.benchmark --fixture does not match retained fixture"
    assert mismatched_fixture["decode_tok_s_per_request"] is None


def test_qwen35_retained_scaling_reference_requires_artifact_path(tmp_path: Path) -> None:
    c1 = tmp_path / "native-baseline-c1.json"
    c1_payload = {
        "prompt_length": 512,
        "decode_tokens": 128,
        "throughput": {"warmed_decode_tok_s": 5.0},
    }
    c1.write_text(json.dumps(c1_payload))
    missing_artifact_path = retained_bench._scaling_reference(c1, default_workload_concurrency=1)
    c1_payload["artifact_path"] = str(tmp_path / "other-native-baseline-c1.json")
    c1.write_text(json.dumps(c1_payload))
    mismatched_artifact_path = retained_bench._scaling_reference(c1, default_workload_concurrency=1)

    assert missing_artifact_path["status"] == "loaded"
    assert missing_artifact_path["reason"] == "artifact_path is missing or not a non-empty string"
    assert missing_artifact_path["decode_tok_s_aggregate"] is None
    assert missing_artifact_path["decode_tok_s_per_request"] is None
    assert missing_artifact_path["reference_artifact_path"] is None
    assert mismatched_artifact_path["status"] == "loaded"
    assert mismatched_artifact_path["reason"] == "artifact_path does not match scaling reference artifact path"
    assert mismatched_artifact_path["decode_tok_s_aggregate"] is None
    assert mismatched_artifact_path["decode_tok_s_per_request"] is None
    assert mismatched_artifact_path["reference_artifact_path"] == str(tmp_path / "other-native-baseline-c1.json")

    serial = tmp_path / "serial-bridge-c2.json"
    serial.write_text(
        json.dumps(
            {
                "artifact_path": str(serial),
                "status": "blocked",
                "workload": {"concurrency": 2, "prompt_tokens_per_request": 512, "gen_tokens_per_request": 128},
                "measurements": {"decode_tok_s_aggregate": 8.0, "decode_tok_s_per_request": 4.0},
            }
        )
    )
    args = argparse.Namespace(c1_baseline_json=c1, serial_bridge_json=serial)
    scaling = retained_bench._build_scaling_comparison(
        args,
        native_decode_tok_s_aggregate=16.0,
        native_decode_tok_s_per_request=8.0,
    )
    assert scaling["complete"] is False
    assert scaling["ratios"]["aggregate_vs_c1"] is None
    assert scaling["ratios"]["aggregate_vs_serial_bridge"] == 2.0


def test_qwen35_batch_correctness_payload_json_rejects_nonfinite() -> None:
    with pytest.raises(ValueError, match="Out of range float values"):
        batch_correctness._payload_json({"bad": float("inf")})

    assert json.loads(batch_correctness._payload_json({"ok": 1.0})) == {"ok": 1.0}


def test_qwen35_primitive_correctness_passed_matches_retained_bounds() -> None:
    assert batch_correctness._REQUIRED_PRIMITIVE_CORRECTNESS_SCHEMA == RETAINED_ARTIFACT_REQUIRED_PRIMITIVE_CORRECTNESS_SCHEMA
    assert batch_correctness._REQUIRED_PRIMITIVE_CORRECTNESS_SEED == RETAINED_ARTIFACT_REQUIRED_PRIMITIVE_CORRECTNESS_SEED
    assert batch_correctness._REQUIRED_PRIMITIVE_CORRECTNESS_SHAPE_FIELDS is RETAINED_ARTIFACT_REQUIRED_PRIMITIVE_CORRECTNESS_SHAPE_FIELDS
    assert batch_correctness._PRIMITIVE_CORRECTNESS_NUMPY_MAX_ABS_LIMIT == RETAINED_ARTIFACT_PRIMITIVE_CORRECTNESS_NUMPY_MAX_ABS_LIMIT
    assert c_sweep._REQUIRED_PRIMITIVE_CORRECTNESS_SCHEMA == RETAINED_ARTIFACT_REQUIRED_PRIMITIVE_CORRECTNESS_SCHEMA
    assert c_sweep._REQUIRED_PRIMITIVE_CORRECTNESS_SEED == RETAINED_ARTIFACT_REQUIRED_PRIMITIVE_CORRECTNESS_SEED
    assert c_sweep._REQUIRED_PRIMITIVE_CORRECTNESS_SHAPE_FIELDS is RETAINED_ARTIFACT_REQUIRED_PRIMITIVE_CORRECTNESS_SHAPE_FIELDS
    assert c_sweep._PRIMITIVE_CORRECTNESS_NUMPY_MAX_ABS_LIMIT == RETAINED_ARTIFACT_PRIMITIVE_CORRECTNESS_NUMPY_MAX_ABS_LIMIT
    assert retained_bench._REQUIRED_PRIMITIVE_CORRECTNESS_SEED == RETAINED_ARTIFACT_REQUIRED_PRIMITIVE_CORRECTNESS_SEED
    assert retained_bench._REQUIRED_PRIMITIVE_CORRECTNESS_SHAPE_FIELDS is RETAINED_ARTIFACT_REQUIRED_PRIMITIVE_CORRECTNESS_SHAPE_FIELDS
    assert retained_bench._PRIMITIVE_CORRECTNESS_NUMPY_MAX_ABS_LIMIT == RETAINED_ARTIFACT_PRIMITIVE_CORRECTNESS_NUMPY_MAX_ABS_LIMIT
    assert artifact_schema._REQUIRED_PRIMITIVE_CORRECTNESS_SCHEMA == RETAINED_ARTIFACT_REQUIRED_PRIMITIVE_CORRECTNESS_SCHEMA
    assert artifact_schema._REQUIRED_PRIMITIVE_CORRECTNESS_SEED == RETAINED_ARTIFACT_REQUIRED_PRIMITIVE_CORRECTNESS_SEED
    assert artifact_schema._REQUIRED_PRIMITIVE_CORRECTNESS_SHAPE_FIELDS is RETAINED_ARTIFACT_REQUIRED_PRIMITIVE_CORRECTNESS_SHAPE_FIELDS
    assert artifact_schema._PRIMITIVE_CORRECTNESS_NUMPY_MAX_ABS_LIMIT == RETAINED_ARTIFACT_PRIMITIVE_CORRECTNESS_NUMPY_MAX_ABS_LIMIT
    assert batch_correctness._primitive_correctness_passed(0, 0, 0.0, 2e-5) is True
    assert batch_correctness._primitive_correctness_passed(1, 0, 0.0, 1e-8) is False
    assert batch_correctness._primitive_correctness_passed(0, 1, 0.0, 1e-8) is False
    assert batch_correctness._primitive_correctness_passed(0, 0, 5e-7, 1e-8) is False
    assert batch_correctness._primitive_correctness_passed(0, 0, 0.0, math.nan) is False
    assert batch_correctness._primitive_correctness_passed(0, 0, 0.0, -1e-8) is False
    assert batch_correctness._primitive_correctness_passed(0, 0, 0.0, 3e-5) is False
    assert (
        batch_correctness._primitive_correctness_passed(0, 0, 0.0, 1e-8, append_batch_aa_key_mismatch=1)
        is False
    )
    assert (
        batch_correctness._primitive_correctness_passed(0, 0, 0.0, 1e-8, attn_batch_aa_max_abs=1e-8)
        is False
    )


def test_qwen35_batch_correctness_numpy_attention_handles_paged_blocks() -> None:
    query = np.ones((1, 1, 1), dtype=np.float32)
    key_cache = np.ones((1, 2, 2, 1, 1), dtype=np.float32)
    value_cache = np.zeros((1, 2, 2, 1, 1), dtype=np.float32)
    value_cache.reshape(1, 4, 1, 1)[0, :3, 0, 0] = np.array([1.0, 3.0, 5.0], dtype=np.float32)
    out = batch_correctness._numpy_attention(
        query,
        batch_correctness.float_array_to_bf16_bits(key_cache),
        batch_correctness.float_array_to_bf16_bits(value_cache),
        np.array([3], dtype=np.int64),
        scale=1.0,
    )
    assert out.shape == (1, 1, 1)
    assert float(out[0, 0, 0]) == pytest.approx(3.0)


def test_qwen35_batch_correctness_fill_context_cache_rows_crosses_page_boundary() -> None:
    key_cache = np.zeros((1, 2, 2, 1, 1), dtype=np.uint16)
    value_cache = np.zeros_like(key_cache)
    key_f32 = np.arange(4, dtype=np.float32).reshape(1, 2, 2, 1, 1)
    value_f32 = (10.0 + np.arange(4, dtype=np.float32)).reshape(1, 2, 2, 1, 1)
    batch_correctness._fill_context_cache_rows(
        key_cache,
        value_cache,
        key_f32,
        value_f32,
        np.array([3], dtype=np.int64),
    )
    assert batch_correctness._bf16_to_f32(key_cache).reshape(1, 4, 1, 1)[0, :, 0, 0].tolist() == [0.0, 1.0, 2.0, 0.0]
    assert batch_correctness._bf16_to_f32(value_cache).reshape(1, 4, 1, 1)[0, :, 0, 0].tolist() == [10.0, 11.0, 12.0, 0.0]


def test_qwen35_batch_correctness_context_lens_parser_validates_rows() -> None:
    parsed = batch_correctness._parse_context_lens("513,512", rows=2, max_context_len=513)
    assert parsed.tolist() == [513, 512]
    with pytest.raises(ValueError, match="length"):
        batch_correctness._parse_context_lens("513", rows=2, max_context_len=513)
    with pytest.raises(ValueError, match="1..max_context_len"):
        batch_correctness._parse_context_lens("514,512", rows=2, max_context_len=513)


def test_qwen35_batch_correctness_records_visible_hip_device_metadata(monkeypatch) -> None:
    class FakeHipFunc:
        def __init__(self, func):
            self.func = func
            self.argtypes = None
            self.restype = None

        def __call__(self, *args):
            return self.func(*args)

    class FakeHipLibrary:
        def __init__(self) -> None:
            self.hipGetDeviceCount = FakeHipFunc(self._count)
            self.hipGetDevice = FakeHipFunc(self._device)
            self.hipDeviceGetName = FakeHipFunc(self._name)

        @staticmethod
        def _count(count_ptr):
            count_ptr._obj.value = 1
            return 0

        @staticmethod
        def _device(device_ptr):
            device_ptr._obj.value = 0
            return 0

        @staticmethod
        def _name(name_buffer, _length, device):
            assert int(device.value) == 0
            name_buffer.value = b"AMD Radeon RX 7900 XTX"
            return 0

    monkeypatch.setenv("HIP_VISIBLE_DEVICES", "1")
    monkeypatch.delenv("ROCR_VISIBLE_DEVICES", raising=False)
    metadata = batch_correctness._visible_hip_device_metadata(SimpleNamespace(library=FakeHipLibrary()))
    assert metadata == {
        "env": {"HIP_VISIBLE_DEVICES": "1"},
        "hipGetDeviceCount_error": 0,
        "visible_device_count": 1,
        "hipGetDevice_error": 0,
        "current_device": 0,
        "hipDeviceGetName_error": 0,
        "device_name": "AMD Radeon RX 7900 XTX",
    }


