def test_qwen35_retained_generated_token_equality_blockers_cover_c1_rows() -> None:
    equality = {
        "passed": True,
        "skipped": False,
        "comparison": "native_batch_vs_independent_c1",
        "rows": 2,
        "warmup_decode_tokens": 1,
        "gen_tokens_per_request": 2,
        "tokens_per_sequence": 4,
        "batch_sequences": [[0, 7, 9, 10], [100, 107, 109, 110]],
        "c1_sequences": [[0, 7, 9, 10], [100, 107, 109, 110]],
        "mismatches": [],
    }
    assert retained_bench._generated_token_equality_blockers(
        equality,
        expected_concurrency=2,
        expected_decode_tokens=2,
        expected_warmup_decode_tokens=1,
    ) == []

    invalid = json.loads(json.dumps(equality))
    invalid["skipped"] = True
    invalid["comparison"] = "batch_only"
    invalid["rows"] = 3
    invalid["warmup_decode_tokens"] = 0
    invalid["gen_tokens_per_request"] = 3
    invalid["tokens_per_sequence"] = 5
    invalid["batch_sequences"][0] = [0, -1]
    invalid["c1_sequences"][1][0] = 101
    invalid["mismatches"] = [{"row": 1}]
    blockers = retained_bench._generated_token_equality_blockers(
        invalid,
        expected_concurrency=2,
        expected_decode_tokens=2,
        expected_warmup_decode_tokens=1,
    )
    assert "correctness.generated_token_equality.skipped must be false" in blockers
    assert "correctness.generated_token_equality.comparison must be native_batch_vs_independent_c1" in blockers
    assert "correctness.generated_token_equality.rows must match expected concurrency" in blockers
    assert "correctness.generated_token_equality.warmup_decode_tokens must match expected warmup decode tokens" in blockers
    assert "correctness.generated_token_equality.gen_tokens_per_request must match expected decode tokens" in blockers
    assert "correctness.generated_token_equality.tokens_per_sequence must match seed plus warmup plus decode tokens" in blockers
    assert (
        "correctness.generated_token_equality.batch_sequences[0] "
        "length does not match seed plus warmup plus decode tokens"
    ) in blockers
    assert "correctness.generated_token_equality.batch_sequences[0] contains a non-token id" in blockers
    assert "correctness.generated_token_equality.batch_sequences must equal c1_sequences" in blockers
    assert "correctness.generated_token_equality.mismatches must be empty" in blockers


def test_qwen35_retained_execution_token_evidence_blockers_cover_seed_and_decode_suffix() -> None:
    seed_tokens = {"0": {"token_id": 0}, "1": {"token_id": 100}}
    generated_tokens = {
        "0": [{"token_id": 9}, {"token_id": 10}],
        "1": [{"token_id": 109}, {"token_id": 110}],
    }
    equality = {
        "batch_sequences": [[0, 1, 2, 9, 10], [100, 101, 102, 109, 110]],
    }
    assert retained_bench._execution_token_evidence_blockers(
        seed_tokens,
        generated_tokens,
        equality,
        expected_concurrency=2,
        expected_decode_tokens=2,
    ) == []

    invalid_seed_tokens = json.loads(json.dumps(seed_tokens))
    invalid_generated_tokens = json.loads(json.dumps(generated_tokens))
    invalid_seed_tokens["1"]["token_id"] = 101
    invalid_generated_tokens.pop("1")
    invalid_generated_tokens["2"] = [{"token_id": 209}, {"token_id": 210}]
    invalid_generated_tokens["0"] = [{"token_id": 9}]
    blockers = retained_bench._execution_token_evidence_blockers(
        invalid_seed_tokens,
        invalid_generated_tokens,
        equality,
        expected_concurrency=2,
        expected_decode_tokens=2,
    )
    assert "execution.seed_tokens.1.token_id does not match generated-token equality seed" in blockers
    assert "execution.generated_tokens keys do not match expected row ids" in blockers
    assert "execution.generated_tokens.0 length does not match expected decode tokens" in blockers
    assert "execution.generated_tokens.0 does not match generated-token equality decode suffix" in blockers
    assert "execution.generated_tokens.1 is not a token payload list" in blockers


