def test_qwen35_retained_request_observability_blockers_cover_row_evidence() -> None:
    valid = {
        "0": {
            "queue_seconds": 0.1,
            "prefill_seconds": 0.2,
            "decode_seconds": 0.3,
            "kv_pages_owned": 2,
            "kv_pages_peak": 3,
            "bucket_key": "decode:c=2:ctx=512:mask=11:kv=bf16:layers=max_layers=40:top_k=0:experts=0:replay=1:draft=0",
            "admission_blocked_reason": None,
            "finish_reason": "length",
            "admitted_timestamp": 10.0,
            "completion_timestamp": 11.0,
        },
        "1": {
            "queue_seconds": 0.1,
            "prefill_seconds": 0.2,
            "decode_seconds": 0.3,
            "kv_pages_owned": 2,
            "kv_pages_peak": 3,
            "bucket_key": "decode:c=2:ctx=512:mask=11:kv=bf16:layers=max_layers=40:top_k=0:experts=0:replay=1:draft=0",
            "admission_blocked_reason": None,
            "finish_reason": "length",
            "admitted_timestamp": 20.0,
            "completion_timestamp": 22.5,
        },
    }
    assert retained_bench._request_observability_blockers(
        valid,
        expected_concurrency=2,
        expected_mode="decode",
        expected_context_bucket=512,
        expected_active_mask="11",
        expected_kv_storage_dtype="bf16",
        expected_layer_plan="max_layers=40",
        expected_top_k=0,
        expected_experts_per_token=0,
        expected_replay_steps=1,
        expected_draft_depth=0,
    ) == []

    invalid = json.loads(json.dumps(valid))
    invalid["2"] = invalid.pop("1")
    invalid["0"].pop("decode_seconds")
    invalid["0"]["kv_pages_peak"] = 1
    invalid["0"]["completion_timestamp"] = 9.0
    invalid["0"]["bucket_key"] = " "
    blockers = retained_bench._request_observability_blockers(invalid, expected_concurrency=2)
    assert "observability.per_request keys do not match expected row ids" in blockers
    assert "observability.per_request.0.decode_seconds is missing" in blockers
    assert "observability.per_request.0.completion_timestamp is not greater than admitted_timestamp" in blockers
    assert "observability.per_request.0.kv_pages_peak is below kv_pages_owned" in blockers
    assert "observability.per_request.0.bucket_key is not a non-empty string or null" in blockers

    stale_bucket_key = json.loads(json.dumps(valid))
    stale_bucket_key["0"]["bucket_key"] = "decode:c=2:ctx=512:mask=11"
    blockers = retained_bench._request_observability_blockers(stale_bucket_key, expected_concurrency=2)
    assert "observability.per_request.0.bucket_key must include kv and layer-plan axes" in blockers

    mismatched_bucket_key_axes = json.loads(json.dumps(valid))
    mismatched_bucket_key_axes["0"]["bucket_key"] = (
        "prefill:c=3:ctx=1024:mask=101:kv=int8_per_token_head:layers=max_layers=8:"
        "top_k=1:experts=2:replay=2:draft=3"
    )
    blockers = retained_bench._request_observability_blockers(
        mismatched_bucket_key_axes,
        expected_concurrency=2,
        expected_mode="decode",
        expected_context_bucket=512,
        expected_active_mask="11",
        expected_kv_storage_dtype="bf16",
        expected_layer_plan="max_layers=40",
        expected_top_k=0,
        expected_experts_per_token=0,
        expected_replay_steps=1,
        expected_draft_depth=0,
    )
    assert "observability.per_request.0.bucket_key mode must match scheduler decode shape key" in blockers
    assert "observability.per_request.0.bucket_key c axis must match expected concurrency" in blockers
    assert "observability.per_request.0.bucket_key context axis must match scheduler observed decode shape key" in blockers
    assert "observability.per_request.0.bucket_key active-mask axis must match scheduler decode shape key" in blockers
    assert "observability.per_request.0.bucket_key kv axis must match expected KV storage dtype" in blockers
    assert "observability.per_request.0.bucket_key layer-plan axis must match expected layer plan" in blockers
    assert "observability.per_request.0.bucket_key top-k axis must match scheduler decode shape key" in blockers
    assert "observability.per_request.0.bucket_key experts axis must match scheduler decode shape key" in blockers
    assert "observability.per_request.0.bucket_key replay axis must match scheduler decode shape key" in blockers
    assert "observability.per_request.0.bucket_key draft axis must match scheduler decode shape key" in blockers

    observed_later_context_bucket = json.loads(json.dumps(valid))
    observed_later_context_bucket["0"]["bucket_key"] = (
        "decode:c=2:ctx=768:mask=11:kv=bf16:layers=max_layers=40:top_k=0:experts=0:replay=1:draft=0"
    )
    observed_later_context_bucket["1"]["bucket_key"] = (
        "decode:c=2:ctx=768:mask=11:kv=bf16:layers=max_layers=40:top_k=0:experts=0:replay=1:draft=0"
    )
    assert retained_bench._request_observability_blockers(
        observed_later_context_bucket,
        expected_concurrency=2,
        expected_mode="decode",
        expected_context_bucket=512,
        expected_context_buckets={512, 768},
        expected_active_mask="11",
        expected_kv_storage_dtype="bf16",
        expected_layer_plan="max_layers=40",
        expected_top_k=0,
        expected_experts_per_token=0,
        expected_replay_steps=1,
        expected_draft_depth=0,
    ) == []

    invalid_timing = json.loads(json.dumps(valid))
    invalid_timing["1"]["queue_seconds"] = 1.0
    invalid_timing["1"]["prefill_seconds"] = 1.0
    invalid_timing["1"]["decode_seconds"] = 1.0
    invalid_timing["1"]["admitted_timestamp"] = 20.0
    invalid_timing["1"]["completion_timestamp"] = 22.5
    blockers = retained_bench._request_observability_blockers(
        invalid_timing,
        expected_concurrency=2,
    )
    assert "observability.per_request.1.timing components exceed completion latency" in blockers


