    def _accepted_with_int8_kv_policy() -> dict[str, object]:
        payload = json.loads(json.dumps(accepted))
        int8_policy = {
            "policy_class": "FixedPagedKVPolicy",
            "storage_dtype": "int8_per_token_head",
            "resolved_storage_dtype": "int8_per_token_head",
            "requested_scale_dtype": "fp16",
            "scale_metadata_format": {"present": True, "scale_dtype": "fp16", "granularity": "per_token_head"},
        }
        payload["workload"]["kv_storage_dtype"] = "int8_per_token_head"
        payload["workload"]["kv_policy"] = int8_policy
        payload["execution"]["scheduler_metadata"]["decode_shape_key"]["kv_storage_dtype"] = "int8_per_token_head"
        for row in payload["observability"]["per_request"].values():
            row["bucket_key"] = str(row["bucket_key"]).replace(
                ":kv=bf16:",
                ":kv=int8_per_token_head:",
            )
        payload["memory"]["kv_storage_dtype"] = "int8_per_token_head"
        payload["memory"]["kv_policy"] = int8_policy
        int8_gate_flags = (
            " --int8-kv-primitive-cpu-json benchmarks/results/int8-primitive-cpu-c2.json"
            " --int8-kv-primitive-hip-json benchmarks/results/int8-primitive-hip-c2.json"
        )
        payload["commands"]["benchmark"] += int8_gate_flags
        payload["commands"]["profiler"] += int8_gate_flags
        return payload

